INSERT INTO public.activitylogs (id, createdat, secondarykey, updatedat, action, details, entity, entityid, level, useremail, username) VALUES (357786274177024, '2026-05-21 13:33:02.00821', 130, NULL, 'UPDATE', '{
  "id" : 278866077003776,
  "secondaryKey" : 130,
  "name" : "Adult status",
  "description" : "Recurrent report of the Seniors condition",
  "subject" : "Weekly Wellness Update",
  "message" : "Dear {User.fullName}, \n\nI hope this message finds you well. We are writing to share a brief update on name **{Adult.fullName}** and their overall well-being this week.\n\n#### General Condition Summary:\n\n**Selbstreflexion**: Rating: {Adult.selfReflectionSts.value}/10 \n- {Adult.selfReflectionSts.evaluation}.\n- {Adult.selfReflectionSts.description}.\n\n**Relationship**: Rating: {Adult.relationshipsSts.value}/10\n- {Adult.relationshipsSts.evaluation}.\n- {Adult.relationshipsSts.description}.\n\n**Continuous Growth**: Rating: {Adult.continuousGrowthSts.value}/10 \n- {Adult.continuousGrowthSts.evaluation}.\n- {Adult.continuousGrowthSts.description}.\n\n\nViele Grüße\n<div style=\"text-align: right; max-width: 400px;\">\n  <div>\n    <img src=\"{GlobalProperty.signature}\" alt=\"Signature\" style=\"max-width: 200px; height: auto;\">\n  </div>\n  <div> \n    Sauer Sitrone\n  </div>\n  <div style=\"font-size: 14px; color: #555;\">\n    Dein Tamagotchi-Begleiter\n  </div>\n</div>",
  "type" : "MARKDOW",
  "audience" : "INTERNAL",
  "isNewsLetter" : true,
  "newsFrequency" : "WEEKLY",
  "newEntity" : false
}', 'de.simone.backend.Mailing', 278866077003776, 'INFO', 'sauer.sitrone@hotmail.com', 'Sauer Zitrone');


