INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448608269, '2025-09-29 12:50:09.750837', 199268075270145, NULL, '7.0', NULL, 'Soziales Leben und Freunde', '0');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448612361, '2025-09-29 12:50:09.751833', 199268075270145, NULL, '8.0', NULL, 'Eigene Familie', '0');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448600065, '2025-09-29 12:50:09.748832', 199268075270145, NULL, '3.4', NULL, 'Wenn nicht in der Nähe, wo wohnten sie dann?', '4');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616459, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.0', NULL, 'Heutiges Leben', '0');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616455, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '8.13', NULL, 'Nennen Sie Beispiele für besondere Ereignisse, an die Sie sich erinnern, z. B. Geburtstage, Jahrestage usw.', '13');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616456, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '8.14', NULL, 'Erinnern Sie sich an lustige Geschichten aus dieser Zeit? Wählen Sie die denkwürdigste aus.', '14');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616457, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '8.15', NULL, 'Erinnern Sie sich an traurige Geschichten aus dieser Zeit? Wählen Sie die denkwürdigste aus.', '15');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616458, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '8.16', NULL, 'Haben Sie etwas gelernt, das es wert ist, an zukünftige Generationen weitergegeben zu werden?', '16');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616460, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.1', NULL, 'Was sind deine Interessen/Aktivitäten? Z. B. Lesen, Stricken, Sport schauen?', '1');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616461, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.2', NULL, 'Was sind deine Lieblingsbeschäftigungen? Aktivitäten oder Gegenstände, Schmuck, Fotos, Kunst usw.', '2');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616462, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.3', NULL, 'Was ist deine Lieblingsfarbe?', '3');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616463, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.4', NULL, 'Was sind deine Lieblingsblumen?', '4');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616464, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.5', NULL, 'Was ist dein Lieblingssport? Rugby, Fußball, Cricket, Leichtathletik? Bist du Fan einer bestimmten Mannschaft?', '5');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616465, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.6', NULL, 'Welches Essen magst/magst du nicht?', '6');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616466, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.7', NULL, 'Siehst du gerne fern, schaust gerne Filme usw.? Welche?', '7');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616467, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.8', NULL, 'Wie wäre es mit Musikhören? Welche Musikrichtung magst du?', '8');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616468, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.9', NULL, 'Wer sind deine Lieblingskünstler oder -bands?', '9');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448616469, '2025-09-29 12:50:09.752831', 199268075270145, NULL, '9.10', NULL, 'Wie sähe dein perfekter Tag aus?', '10');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448620544, '2025-09-29 12:50:09.753831', 199268075270145, NULL, '9.11', NULL, 'Wohin würdest du gehen?', '11');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448620545, '2025-09-29 12:50:09.753831', 199268075270145, NULL, '9.12', NULL, 'Was würdest du tun?', '12');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448620546, '2025-09-29 12:50:09.753831', 199268075270145, NULL, '9.13', NULL, 'Wer wäre dabei?', '13');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448620547, '2025-09-29 12:50:09.753831', 199268075270145, NULL, '9.14', NULL, 'Wer sind die wichtigsten Menschen in deinem Leben?', '14');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448620548, '2025-09-29 12:50:09.753831', 199268075270145, NULL, '9.15', NULL, 'Wenn du heute etwas Neues lernen könntest, z. B. eine neue Fähigkeit oder ein neues Hobby, was wäre das?', '15');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448620549, '2025-09-29 12:50:09.753831', 199268075270145, NULL, '9.16', NULL, 'Wenn du irgendwohin reisen könntest, wo du schon immer hinwolltest, wohin wäre das?', '16');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448591873, '2025-09-29 12:50:09.746305', 199268075270145, '2025-09-29 13:03:54.060511', '1.1', '13/10/1971', 'Wann wurdest du geboren?', '1');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448608272, '2025-09-29 12:50:09.750837', 199268075270145, '2025-11-14 12:54:32.179394', '7.3', 'Sí', 'Hast du geheiratet?', '3');
INSERT INTO public.books (id, createdat, secondarykey, updatedat, chapter, paragraph, question, section) VALUES (274964448591875, '2025-09-29 12:50:09.746305', 199268075270145, '2025-11-14 12:59:25.919953', '1.3', 'En Clínica Santa Luisa, Caracas', 'In welchem Krankenhaus wurdest du geboren?', '3');
