INSERT INTO public.mailings (createdat, id, secondarykey, updatedat, audience, description, name, message, subject, type, isnewsletter, newsfrequency) VALUES ('2025-10-15 12:22:03.279272', 280619851223040, 130, '2025-10-15 13:34:34.098509', 'EXTERNAL', 'Recurrent report of the Seniors condition', 'Adult status', 'Dear {User.fullName}

