INSERT INTO public.mailings (createdat, id, secondarykey, updatedat, audience, description, name, message, subject, type, isnewsletter, newsfrequency) VALUES ('2026-02-05 14:24:49.647511', 121, 130, '2026-02-11 14:49:45.706506', 'EXTERNAL', 'Warnung beim Anmelden auf neuem Gerät', 'Anmeldewarnung', 'Hallo {User.firstName}
 
Jemand hat sich gerade in der Nähe von {LoginDevice.cityName}, {LoginDevice.regionName} bei deinem Sitrone-Konto angemeldet. 

<br>📍 {LoginDevice.cityName}, {LoginDevice.regionName}
<br>💻 {LoginDevice.os}
<br>🌐 {LoginDevice.browser}
<br>⌚ {LoginDevice.lastSignIn.format(''yyyy-MM-dd HH:mm'')}


<br>**[Das war ich nicht]({GlobalProperty.host}Confirmation/{LoginDevice.id})**
 
<br>Wenn du das warst, kannst du diese E-Mail ignorieren.
 
Du fragst dich, ob diese E-Mail wirklich von uns ist? Im Hilfebereich kannst du nachsehen: **[Sicherheitshilfe](www.SauerSitrone.de/help/check-email)** 
 
Wir benachrichtigen dich weiterhin, wenn dein Benutzername und dein Password zur Anmeldung in einem neuen Browser oder auf einem neuen Gerät verwendet werden.
 
Viele Grüße

Sauer Security-team


if you pressed "das war ich nicht" by error, you can de process undo by hier clicken.
', 'Warnung beim Anmelden auf neuem Gerät', 'MARKDOW', false, 'WEEKLY');
INSERT INTO public.mailings (createdat, id, secondarykey, updatedat, audience, description, name, message, subject, type, isnewsletter, newsfrequency) VALUES (NULL, 101, 130, '2026-03-20 10:58:58.601841', 'INTERNAL', 'Email template for 2fa code confirmation.', 'Bestätigungscode', 'Lieber Sitrone-Nutzer,

wir haben eine Anfrage für den Zugriff auf Ihr Sitrone-Konto **{User.email}** über Ihre E-Mail-Adresse erhalten. Ihr Bestätigungscode lautet:

## {User.confirmationCode}

Falls Sie diesen Code nicht angefordert haben, versucht möglicherweise eine andere Person, auf das GoodFunds-Konto **{User.email}** zuzugreifen. Geben Sie diesen Code nicht weiter.

Mit freundlichen Grüßen

<div style="text-align: right; max-width: 400px;">
    <img src="{GlobalProperty.signature}" alt="Signature" style="max-width: 200px; height: auto;">
  <div> 
    Sauer Sitrone
  </div>
  <div style="font-size: 14px; color: #555;">
    Dein Tamagotchi-Begleiter
  </div>
</div>', 'Ihre 2FA Bestätigungscode', 'MARKDOW', false, NULL);
