INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357774704025600, '2026-05-21 12:45:57.26455', 295514619002880, NULL, NULL, '', NULL, NULL, 'An Ebola‑infected American doctor is being treated under the highest safety standards in a specialized isolation unit in the German capital, Berlin. The facilities are considered to be among the best equipped worldwide.', NULL, 'https://www.dw.com/en/ebola-patient-in-berlin-why-germany-s-helping/a-77237887?maca=en-rss-en-all-1573-rdf', '2026-05-21 12:41:00+00', 'Ebola patient in Berlin: Why Germany''s helping', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357774704029696, '2026-05-21 12:45:57.265694', 295514619002880, NULL, NULL, '', NULL, NULL, 'Airstrikes in Nigeria led by the US have weakened the influence of the so-called Islamic State (IS) terror group. The strike shows an expanding US role, but analysts warn of limited long‑term impact and civilian risks.', NULL, 'https://www.dw.com/en/is-the-us-deepening-its-military-involvement-in-nigeria/a-77236534?maca=en-rss-en-all-1573-rdf', '2026-05-21 12:40:00+00', 'Is the US deepening its military involvement in Nigeria?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357774706372608, '2026-05-21 12:45:57.837354', 295500424519680, NULL, 'DIE ZEIT: Sport - Yannick von Eisenhart Rothe, Sophia Reddig, Leon Ginzel', 'Sport', NULL, NULL, 'Der deutsche Kader für die Weltmeisterschaft steht. Bundestrainer Nagelsmann begründet die Neuer-Rückkehr und verteidigt seine Kommunikation gegen Kritik. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-05-21 12:38:53+00', 'Fußballweltmeisterschaft 2026: »Jeder weiß, welche Aura den Manu umgibt«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555656, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'KNDS ist eine der großen Rüstungsfirmen Europas und soll an die Börse. Lange wurde um einen Einstieg der Bundesregierung bei dem deutsch-französischen Konzern gerungen. Nun gibt es eine Entscheidung.', 'b0400703-f892-496b-b661-0855da7931a9', 'https://www.tagesschau.de/inland/innenpolitik/knds-110.html', '2026-05-20 22:51:26+00', 'Bundesregierung steigt bei Panzerbauer KNDS ein', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555657, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ein Streik bei Samsung hätte weltweit Auswirkungen. In letzter Minute konnte er abgewendet werden - vorerst zumindest. Der südkoreanische Elektronikkonzern ist der weltweit größte Produzent von Speicherchips.', 'f7f5cfe5-6e1f-4584-91a0-49af63d8e633', 'https://www.tagesschau.de/wirtschaft/unternehmen/samsung-generalstreik-tarifstreit-102.html', '2026-05-20 18:58:55+00', 'Samsung wendet Streik vorerst ab', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559744, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor 30 Jahren wurden zwei US-Flugzeuge von der kubanischen Luftwaffe abgeschossen. Vier Menschen starben. Nun will das US-Justizministerium Kubas ehemaligen Präsidenten Raúl Castro wegen des Vorfalls anklagen.', '717f5a6d-2e56-45da-92b4-23aa94c500b2', 'https://www.tagesschau.de/ausland/amerika/castro-klage-100.html', '2026-05-21 06:45:47+00', 'US-Justizministerium kündigt Klage gegen Kubas Ex-Staatschef Raúl Castro an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559745, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Chinas Staats- und Parteichef Xi und Russlands Präsident Putin haben in Peking Zusammenhalt demonstriert - bei einer geplanten Gaspipeline gab es aber keine konkrete Einigung.', '8bca05df-294d-4f33-a082-9852d1961e75', 'https://www.tagesschau.de/ausland/putin-in-peking-100.html', '2026-05-20 18:34:55+00', 'Xi und Putin betonen gute Beziehungen bei Staatsbesuch in Peking', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559746, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Polizeiminister Ben-Gvir gehört zu den kontroversesten Mitgliedern des israelischen Kabinetts. Jetzt hat er ein Video gepostet, in dem Aktivisten der Gaza-Flotte vorgeführt werden - das sorgt international für Kritik.', 'acb42971-6d61-421f-8edb-f50147f1010e', 'https://www.tagesschau.de/ausland/europa/gaza-aktivisten-100.html', '2026-05-20 18:07:24+00', 'Israels Polizeiminister postet Video und sorgt für Empörung', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559747, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Im Koalitionsvertrag hatten CDU, CSU und SPD bereits festgehalten, dass sie gegen überhöhte Preise beim Wiederverkauf von Tickets vorgehen wollen. Geschehen ist das noch nicht. Die Musiker der Toten Hosen machen nun Druck.', '31ec9097-5628-44da-9a78-a5f6f9f13e76', 'https://www.tagesschau.de/kultur/tote-hosen-ticketpreise-100.html', '2026-05-20 17:20:16+00', 'Tote Hosen fordern von Bundesregierung Gesetz gegen Ticketwucher', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559748, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Wegen des Iran-Kriegs sind auch in Großbritannien die Energiepreise gestiegen. Die Regierung will den Import von Treibstoff erlauben, der im Ausland aus russischem Öl raffiniert wurde. Die Opposition ist entsetzt.', 'f28cccf3-0e0e-47a4-b91c-e783a554e46a', 'https://www.tagesschau.de/ausland/europa/grossbritannien-treibstoffe-russland-100.html', '2026-05-20 16:58:10+00', 'Energiekrise: Großbritannien lockert Ölsanktionen gegen Russland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559749, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Sinkende Ölpreise haben am Nachmittag auch deutschen Aktien einen Schub gegeben. Zugleich sorgen die steigenden Anleiherenditen weiterhin für Unruhe unter den Anlegern.', 'bc30b580-a8a7-4bd5-9f32-5db072099410', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/dax-nikkei-nvidia-100.html', '2026-05-20 16:31:49+00', 'Marktbericht: Zwischen Hoffnung und Eskalationsangst', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559750, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor allem wegen gestiegener Einfuhren ist China weiterhin das Land, das am meisten Warenaustausch mit Deutschland betreibt. Die deutschen Ausfuhren in die Volksrepublik sind dagegen zum Jahresbeginn stark zurückgegangen.', 'b237fe1a-d9e3-457a-bb53-c57a37e1960b', 'https://www.tagesschau.de/wirtschaft/konjunktur/deutschland-handel-china-usa-100.html', '2026-05-20 16:29:56+00', 'China-Importe steigen, deutsche Exporte in das Land brechen ein', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559751, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'In Israel wird eine vorgezogene Parlamentswahl wahrscheinlicher: Die Knesset hat in einer ersten Lesung für ihre Auflösung gestimmt - bis zu möglichen Neuwahlen gibt es aber noch einige Hürden. Von Bettina Meier.', 'b8bac5ec-62dc-4c7f-96f9-eb721976fb60', 'https://www.tagesschau.de/ausland/asien/israel-parlament-112.html', '2026-05-20 16:23:10+00', 'Israelisches Parlament stimmt für Selbstauflösung - erster Schritt zu Neuwahlen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559752, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Gefahr einer Pandemie sieht die WHO weiterhin nicht. Sie rechnet aber damit, dass sich Ebola in DR Kongo weiter ausbreitet. Ein infizierter US-Arzt ist zur Behandlung in Deutschland - auch seine Familie soll nun nach Berlin kommen.', 'e819cef4-e314-43f7-a5cf-43d4dd2b52b9', 'https://www.tagesschau.de/ausland/afrika/ebola-who-112.html', '2026-05-20 15:39:17+00', 'WHO warnt vor noch mehr Ebola-Fällen in DR Kongo', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559753, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Weniger Sonderfahrten, keine Präsenzpflicht im Theorieunterricht: Die Bundesregierung will den Führerschein digitaler, einfacher und günstiger machen. Das Kabinett hat eine Reform auf den Weg gebracht - was soll sich ändern?', '5d82e1f8-e90a-4943-a3eb-0b3344da5965', 'https://www.tagesschau.de/inland/innenpolitik/kabinett-beschluss-fuehrerschein-reform-102.html', '2026-05-20 15:16:13+00', 'So soll der Führerschein günstiger werden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438559754, '2026-05-21 10:34:39.953924', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die italienische UniCredit besitzt schon fast 27 Prozent an der Commerzbank. Deren Übernahmeangebot hält die Führungsspitze der Privatbank für zu niedrig. Und was sagen die Anleger dazu? Von Ingo Nathusius.', '3d3556c2-5152-46b9-bc68-b598a09c0878', 'https://www.tagesschau.de/wirtschaft/finanzen/commerzbank-hauptversammlung-unicredit-100.html', '2026-05-20 15:08:25+00', 'Wie die Commerzbank-Aktionäre zu einer Übernahme durch UniCredit stehen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357774706376704, '2026-05-21 12:45:57.838353', 295500424519680, NULL, 'DIE ZEIT: Sport - Maxim Nägele', 'Sport', NULL, NULL, 'Drei Wochen vor der Fußball-WM präsentiert Bundestrainer Nagelsmann den deutschen Kader. Mit dabei ist Weltmeister Neuer, El Mala fehlt überraschend.', '{urn:uuid:7fb98a7c-3a7a-405d-aca0-4925db79debd}', 'https://www.zeit.de/sport/2026-05/fussball-wm-kader-nagelsmann-neuer', '2026-05-21 12:36:55+00', 'Fußballweltmeisterschaft 2026: Neuer, Pavlović und Undav im DFB-Kader für die WM', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357774706376705, '2026-05-21 12:45:57.838353', 295500424519680, NULL, 'DIE ZEIT: Zeitgeschehen - Sophia Reddig', 'Zeitgeschehen', NULL, NULL, '2009 stürzte ein Flugzeug auf dem Weg von Rio de Janeiro nach Paris ab. Ein Gericht verurteilte die Airline und den Flugzeugbauer im Berufungsprozess zu einer Geldstrafe.', '{urn:uuid:7f267ee4-87b1-409e-a448-674cc31add2b}', 'https://www.zeit.de/gesellschaft/zeitgeschehen/2026-05/air-france-absturz-2009-af447-airbus-a330-paris', '2026-05-21 12:30:13+00', 'Air-France-Absturz 2009: Air France und Airbus nach Flugzeugabsturz mit 228 Toten verurteilt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357774706835456, '2026-05-21 12:45:57.951413', 295853820891136, NULL, NULL, '', NULL, NULL, 'Es geht mal wieder um viel Geld an der Wall Street. Denn mit den geplanten Börsengängen aus dem US-Tech-Sektor, allen voran Elon Musks Raumfahrtkonzern SpaceX, werden neue Dimensionen erreicht.', 'f7bfa4fe-86f4-4665-b316-b356618751bb', 'https://www.tagesschau.de/wirtschaft/finanzen/usa-boersengaenge-emissionen-100.html', '2026-05-21 12:41:20+00', 'Geplante Börsengänge von Tech-Giganten versprechen der Wall Street Milliarden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357777570611200, '2026-05-21 12:57:37.114347', 295500424519680, NULL, 'DIE ZEIT: Zeitgeschehen - Sophia Reddig', 'Zeitgeschehen', NULL, NULL, '2009 stürzte ein Flugzeug auf dem Weg von Rio de Janeiro nach Paris ab. Ein Gericht verurteilte die Airline und den Flugzeugbauer im Berufungsprozess zu einer Geldstrafe.', '{urn:uuid:7f267ee4-87b1-409e-a448-674cc31add2b}', 'https://www.zeit.de/gesellschaft/zeitgeschehen/2026-05/air-france-absturz-2009-af447-airbus-a330-paris', '2026-05-21 12:53:42+00', 'Air-France-Absturz 2009: Air France und Airbus nach Flugzeugabsturz mit 228 Toten verurteilt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357777570611201, '2026-05-21 12:57:37.114347', 295500424519680, NULL, 'DIE ZEIT: Sport - Yannick von Eisenhart Rothe, Sophia Reddig, Leon Ginzel', 'Sport', NULL, NULL, 'Der deutsche Kader für die Weltmeisterschaft steht. Bundestrainer Nagelsmann begründet die Neuer-Rückkehr und verteidigt seine Kommunikation gegen Kritik. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-05-21 12:50:56+00', 'Fußballweltmeisterschaft 2026: »Jeder weiß, welche Aura den Manu umgibt«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357777570615296, '2026-05-21 12:57:37.115346', 295500424519680, NULL, 'DIE ZEIT: Sport - Oliver Fritsch, Nico Horn, Christian Spiller, Julius Tröger, Jakob Weber', 'Sport', NULL, NULL, 'Julian Nagelsmann hat seinen WM-Kader vorgestellt. Mit Manuel Neuer im Tor, einem finnischen Muttersprachler und einem Stürmer, der Esel liebt. Das sind die 27 WM-Fahrer.', '{urn:uuid:01cc5f53-288c-4e57-9c35-cc740f378ce1}', 'https://www.zeit.de/sport/2026-05/dfb-kader-fussball-wm-2026-nationalmannschaft-julian-nagelsmann', '2026-05-21 12:47:33+00', 'DFB-Kader für die Fußball-WM: Diese Mannschaft möchte Weltmeister werden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357777570615297, '2026-05-21 12:57:37.115346', 295500424519680, NULL, 'DIE ZEIT: Zeitgeschehen - Alexander Eydlin', 'Zeitgeschehen', NULL, NULL, 'Die Bundesanwaltschaft wirft zwei Männern vor, im Auftrag Irans Mordanschläge auf Juden geplant zu haben. Unter ihnen soll Zentralratspräsident Schuster gewesen sein.', '{urn:uuid:9360f871-d2b7-4c54-b4cc-fdffe14415b3}', 'https://www.zeit.de/gesellschaft/zeitgeschehen/2026-05/bundesanwaltschaft-iran-anschlagsplaene-mord-juden-anklage', '2026-05-21 12:45:58+00', 'Bundesanwaltschaft: Anklage wegen mutmaßlicher iranischer Anschlagspläne erhoben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357777571057664, '2026-05-21 12:57:37.223259', 295853820891136, NULL, NULL, '', NULL, NULL, 'Eine blinde Frau soll nach einer Operation zur Reha. Dort nimmt man sie aber nicht auf - wegen ihrer Blindheit. Die Patientin klagt auf Entschädigung. Diese Klage lehnte der BGH nun in letzter Instanz ab.', 'c9d6ad10-bef1-4311-a813-512f05c4f800', 'https://www.tagesschau.de/inland/gesellschaft/bgh-klage-blinde-diskriminierung-100.html', '2026-05-21 12:54:18+00', 'Blinde Patientin scheitert mit Klage gegen Rehaklinik am BGH', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357777571569664, '2026-05-21 12:57:37.348528', 295514619002880, NULL, NULL, '', NULL, NULL, 'Latvia''s military said NATO planes responded to at least one drone flying in its airspace. It''s the latest in a string of such incidents in the Baltic, one of which eventually toppled Latvia''s government.', NULL, 'https://www.dw.com/en/latvia-scrambles-nato-jets-in-drone-alert-the-latest-of-several-in-baltic/a-77244356?maca=en-rss-en-all-1573-rdf', '2026-05-21 12:49:00+00', 'Latvia scrambles NATO jets in drone alert, the latest of several in Baltic', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512341504, '2026-05-27 14:21:20.389931', 295500424519680, NULL, 'DIE ZEIT: Arbeit - Lisa Röther', 'Arbeit', NULL, NULL, 'Hochgebildete Menschen starten später in den Job. Trotzdem bleiben sie mit Abstand am längsten im Arbeitsleben, zeigt eine neue Studie. Das hat zwei Gründe.', '{urn:uuid:2d11deef-d9fc-4611-9fe2-fc7cd53905ba}', 'https://www.zeit.de/arbeit/2026-05/laengste-lebensarbeitszeit-hohe-bildung-studie', '2026-05-27 14:04:13+00', 'Arbeitsmarkt: Menschen mit hoher Bildung haben die längste Lebensarbeitszeit', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512357888, '2026-05-27 14:21:20.39293', 295500424519680, NULL, 'DIE ZEIT: Sport - Yannick von Eisenhart Rothe, Jona Spreter, Luis Kumpfmüller', 'Sport', NULL, NULL, 'Oliver Baumann wird im vorletzten Testspiel Manuel Neuer vertreten. Deutschlands Nummer 1 kuriert seine Wadenverletzung weiter aus. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-05-27 14:02:54+00', 'Fußballweltmeisterschaft 2026: Manuel Neuer auch für Testspiel gegen Finnland noch nicht fit', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512361984, '2026-05-27 14:21:20.393932', 295500424519680, NULL, 'DIE ZEIT: Ausland - Alexander Eydlin', 'Ausland', NULL, NULL, 'Für sicherheitsrelevante Frequenzen will die EU weniger Lizenzen an ausländische Satellitendienste vergeben. Zwei Drittel davon sollen EU-Anbietern vorbehalten sein.', '{urn:uuid:72715f3e-9591-4cfc-a631-b8bff8fd92ed}', 'https://www.zeit.de/politik/ausland/2026-05/satellitendienste-eu-frequenzen-lizenzen-abhaengigkeit-usa', '2026-05-27 13:59:15+00', 'Satellitendienste: EU-Kommission will Abhängigkeit von USA beim Mobilfunk reduzieren', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357778878087168, '2026-05-21 13:02:56.322654', 295500424519680, NULL, 'DIE ZEIT: Sport - Eric Voigt', 'Sport', NULL, NULL, 'Den FC Thun führte Mauro Lustrinelli als Trainer jüngst zur Schweizer Meisterschaft. Nun wagt er den Sprung in die Bundesliga und wird Coach bei Union Berlin.', '{urn:uuid:5494b628-d5af-43d3-bcaa-947fccf03196}', 'https://www.zeit.de/sport/2026-05/mauro-lustrinelli-union-berlin-trainer-fc-thun', '2026-05-21 12:56:14+00', 'Fußballbundesliga: Mauro Lustrinelli wird neuer Trainer bei Union Berlin', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512361985, '2026-05-27 14:21:20.393932', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Luis Kumpfmüller', 'Deutschland', NULL, NULL, 'Wer selbst Strom erzeugt, soll sich nach Plänen der Bundesnetzagentur künftig stärker an den Kosten für das Stromnetz beteiligen. Das sei ein »Gebot der Fairness«.', '{urn:uuid:febc32e8-3ada-400c-85d5-469c655e531c}', 'https://www.zeit.de/politik/deutschland/2026-05/bundesnetzagentur-netzentgelte-strom-reform-solaranlagen', '2026-05-27 13:48:01+00', 'Bundesnetzagentur: Solaranlagenbesitzer sollen stärker an Netzkosten beteiligt werden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357743787855872, '2026-05-21 10:40:09.371629', 295514619002880, NULL, NULL, '', NULL, NULL, 'Seasonal smog is a major public health problem in Thailand. Long-delayed legislation aims to stop air pollution before it starts, but enforcement could present a problem.', NULL, 'https://www.dw.com/en/thailand-revives-bill-to-clear-the-air-of-toxic-smog/a-77239344?maca=en-rss-en-all-1573-rdf', '2026-05-21 10:34:00+00', 'Thailand revives bill to clear the air of toxic smog', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512361986, '2026-05-27 14:21:20.393932', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Jona Spreter', 'Wirtschaft', NULL, NULL, 'Ein Fußballgroßereignis allein verkauft nicht zwingend mehr Bier, meint der Brauer-Bund. Die deutsche Nationalmannschaft müsse schon erfolgreich sein.', '{urn:uuid:f55c0f44-04c9-4398-bd64-d2ed28903638}', 'https://www.zeit.de/wirtschaft/2026-05/fussball-wm-deutschland-brauereien-bier', '2026-05-27 13:35:37+00', 'Fußballweltmeisterschaft: Deutschlands Brauereien hoffen auf Erfolg des DFB-Teams bei der WM', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512361987, '2026-05-27 14:21:20.393932', 295500424519680, NULL, 'DIE ZEIT: Film - Juliane Liebert', 'Film', NULL, NULL, 'In der Amazon-Serie »Spider-Noir« spielt Nicolas Cage einen Detektiv, der säuft wie niemand im Fernsehen seit Don Draper. Und das ist nicht mal seine größte Superkraft.', '{urn:uuid:ba00063c-5f5e-4b1b-9ae4-120adeda8f54}', 'https://www.zeit.de/feuilleton/film/2026-05/spider-noir-marvel-serie-prime-video-nicolas-cage', '2026-05-27 13:33:24+00', '»Spider-Noir«: Nebenberuf: Spider-Man', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921512366080, '2026-05-27 14:21:20.394933', 295500424519680, NULL, 'DIE ZEIT: Ausland - Anna Sauerbrey', 'Ausland', NULL, NULL, 'Donald Trump sucht nach einem Ausweg aus dem Iran-Dilemma, doch seine Aktionen wirken zunehmend verzweifelt. Mittlerweile ist der Druck auch innenpolitisch enorm.', '{urn:uuid:0a189b78-dbd0-4ba7-b3ce-fa9464557c46}', 'https://www.zeit.de/2026/24/donald-trump-iran-strasse-von-hormus-abkommen', '2026-05-27 13:31:15+00', 'Donald Trump und der Iran: In die Ecke regiert', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513046016, '2026-05-27 14:21:20.560104', 295853820891136, NULL, NULL, '', NULL, NULL, 'Israel hat den neuen Führer der Hamas im Gazastreifen, Odeh, getötet. Nach Angaben der Armee kam er bei einem Luftangriff auf Gaza-Stadt ums Leben. Odeh soll maßgeblich am Massaker vom 7. Oktober 2023 beteiligt gewesen sein.', '66d53edf-b3d9-4477-8362-680145cf637b', 'https://www.tagesschau.de/ausland/asien/israel-hamas-fuehrer-tod-100.html', '2026-05-27 14:07:56+00', 'Hamas bestätigt Tod des neuen Militärchefs im Gazastreifen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513046017, '2026-05-27 14:21:20.560104', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Bundesregierung will den Sicherheitsbehörden mehr Möglichkeiten bei der Abwehr von Cyberangriffen geben. Bundesbehörden sollen sich laut einem Kabinettsentwurf künftig nicht nur verteidigen, sondern auch Gegenangriffe starten können.', '48546c76-5b3f-456a-a429-fd6458f17cd1', 'https://www.tagesschau.de/inland/innenpolitik/cyberabwehr-106.html', '2026-05-27 13:37:19+00', 'Cyberabwehr: BSI und Polizei sollen mehr Befugnisse erhalten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513050112, '2026-05-27 14:21:20.561104', 295853820891136, NULL, NULL, '', NULL, NULL, 'Handy, Router und Computer - Einfallstore für Hacker. Im vergangenen Jahr wurden elf Prozent der Internetnutzer in Deutschland Opfer von Cyberkriminalität. Wie kann man sich am besten gegen Angriffe wappnen? Von Stefan Zanev.', 'e66ab4d8-9d3e-41e0-abc1-f2898599d661', 'https://www.tagesschau.de/wissen/technologie/cybersicherheit-120.html', '2026-05-27 13:31:41+00', 'So kann man sich vor Hackern schützen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513050113, '2026-05-27 14:21:20.561104', 295853820891136, NULL, NULL, '', NULL, NULL, 'Im Zusammenhang mit der Messerattacke am Berliner Holocaust-Mahnmal im Februar 2025 ist ein weiterer Mann festgenommen worden. Er soll den inzwischen verurteilten Angreifer zu der Tat ermutigt haben.', 'tagesschau_fm-story-rbb_neue-festnahme-angriff-holocaust-mahnmal-berlin-messer', 'https://www.tagesschau.de/inland/regional/berlin/neue-festnahme-messerattacke-holocaust-mahnmal-100.html', '2026-05-27 12:59:00+00', 'Neue Festnahme nach Messerattacke am Berliner Holocaust-Mahnmal', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513050114, '2026-05-27 14:21:20.561104', 295853820891136, NULL, NULL, '', NULL, NULL, 'Sexualisierte Gewalt ist ein Problem - auch im Breitensport. Schutzkonzepte sollen Mitarbeiter und Ehrenamtliche in Sportvereinen sensibilisieren. Doch für viele Vereine ist das eine Herausforderung. Online-Tools können helfen. Von Lea Schön.', '605c1e86-a0cc-43bf-95bd-a34233614353', 'https://www.tagesschau.de/inland/gesellschaft/sexualisierte-gewalt-sportverein-100.html', '2026-05-27 12:28:32+00', 'Was tun Sportvereine zur Prävention von sexualisierter Gewalt?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513054208, '2026-05-27 14:21:20.562137', 295853820891136, NULL, NULL, '', NULL, NULL, 'Auch die japanische Börse ist auf Rekordjagd. Gerade hat der Nikkei die Marke von 66.000 Punkten überschritten. Japan liegt wieder im Trend - nach Jahrzehnten der Stagnation.', 'a004c049-6886-4b81-920d-aae8794a347a', 'https://www.tagesschau.de/wirtschaft/finanzen/marktbericht-rekord-nikkei-japan-100.html', '2026-05-27 11:55:41+00', 'Nikkei auf Rekordhoch: Investoren blicken wieder nach Japan', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513054209, '2026-05-27 14:21:20.562137', 295853820891136, NULL, NULL, '', NULL, NULL, 'Fünf in einer Höhle in Laos vermisste Dorfbewohner sind lebend gefunden worden. Zwei weitere Menschen würden noch vermisst, teilten Rettungskräfte mit. Eine Sturzflut hatten den Goldsuchern den Rückweg abgeschnitten.', 'fbabad9a-049d-4ba8-a344-3654d45b12ab', 'https://www.tagesschau.de/ausland/asien/laos-hoehle-vermisste-100.html', '2026-05-27 12:06:37+00', 'Retter finden fünf Überlebende in überfluteter Höhle in Laos', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513054210, '2026-05-27 14:21:20.562137', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das Bundeskabinett hat Änderungen im Baurecht zugestimmt. Die geplanten Regelungen sollen vor allem Kommunen helfen, schneller neue Wohnungen bauen und "Schrottimmobilien" notfalls sogar enteignen zu können.', '8cb04594-9dd6-48ba-a512-6c56642e1fb8', 'https://www.tagesschau.de/inland/innenpolitik/baurecht-novelle-102.html', '2026-05-27 11:48:34+00', 'Neue Regeln im Baurecht sollen Wohnungsbau beschleunigen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513058304, '2026-05-27 14:21:20.563139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Russland kündigt weitere schwere Angriffe auf Kiew an. Für die Bundesregierung ein Grund mehr, die Unterstützung für die Ukraine zu intensivieren. Das Ziel: den russischen Präsidenten Putin zu Verhandlungen bewegen. Von Christina Nagel.', 'e3ad2bfb-67e9-4b1f-9150-7a18996f7f28', 'https://www.tagesschau.de/inland/innenpolitik/ukraine-unterstuetzung-deutschland-100.html', '2026-05-27 09:49:09+00', 'Ukraine-Politik: Putins Drohkulisse - und Deutschlands Antwort', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513058305, '2026-05-27 14:21:20.563139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Regierungspartei von Ministerpräsident Sánchez steht wegen Korruptionsvorwürfen unter Druck. Nun hat die spanische Polizei die Parteizentrale in Madrid durchsucht. Demnach geht es um mögliche illegale Parteifinanzierung.', '3bf40395-ee71-47bf-93ed-480b5e3465ca', 'https://www.tagesschau.de/ausland/europa/durchsuchung-psoe-100.html', '2026-05-27 09:48:53+00', 'Wegen Korruptionsskandal: Durchsuchung bei Regierungspartei in Madrid', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513062400, '2026-05-27 14:21:20.564137', 295853820891136, NULL, NULL, '', NULL, NULL, 'Auch Luxusmarken setzten auf Elektroantrieb. Nach Herstellern wie Porsche, Rolls-Royce oder Maserati steigt auch Ferrari ins exklusive E-Auto-Segment ein. Kann eine solche Strategie aufgehen? Von Claudia Wehrle.', '37ddff07-0ea4-4ba4-8f82-ae320dbe5cf0', 'https://www.tagesschau.de/wirtschaft/technologie/ferrari-elektromobilitaet-superreiche-100.html', '2026-05-27 09:44:23+00', 'Jetzt steigt auch Ferrari ein: Elektromobilität für Superreiche', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513062401, '2026-05-27 14:21:20.564137', 295853820891136, NULL, NULL, '', NULL, NULL, 'Wer mehr als 100 Millionen Dollar besitzt, gilt als superreich. In Deutschland gehören Tausende Menschen dazu - Tendenz steigend, wie eine Studie zeigt. Zusammen mit den Multimillionären halten sie über die Hälfte des Finanzvermögens.', 'ffbadf82-fd15-435b-bb64-dd43b72f227b', 'https://www.tagesschau.de/wirtschaft/finanzen/superreiche-deutschland-vermoegen-100.html', '2026-05-27 09:39:32+00', 'Zahl der Superreichen in Deutschland steigt stark', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513062402, '2026-05-27 14:21:20.564137', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der deutsche Leitindex ist mit Gewinnen in die Wochenmitte gestartet, unterstützt von guten Vorgaben aus Japan und den USA. Im Fokus der Anleger stehen heute vor allem die Konjunktur und politische Termine.', '0e955947-1099-4b50-a9b2-e9a1da0f63b1', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-dow-jones-iran-krieg-100.html', '2026-05-27 08:33:11+00', 'Marktbericht: DAX kann Iran-Sorgen abschütteln', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513066496, '2026-05-27 14:21:20.56514', 295853820891136, NULL, NULL, '', NULL, NULL, 'In Singapur leben Otter mitten in der Stadt - zwischen 40-stöckigen Hochhäusern, Baustellenlärm und vollen Restaurants. Doch das war nicht immer so. Und es bringt auch Probleme. Von Jennifer Johnston.', 'dd18222b-d20b-4bec-8496-50a345e03b32', 'https://www.tagesschau.de/ausland/asien/otter-singapur-100.html', '2026-05-27 08:22:20+00', 'Zwischen Hochhäusern in Singapur - Wenn Otter Nachbarn werden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513066497, '2026-05-27 14:21:20.56514', 295853820891136, NULL, NULL, '', NULL, NULL, 'In der Industrie mehren sich die Alarmsignale: Der Jobabbau geht rasant weiter, wer kann, verlagert ins Ausland. Viele Unternehmer fühlen sich von der Politik alleingelassen und gegängelt. Von Axel John.', 'e7892099-d3a4-4723-94c4-fd8c19477245', 'https://www.tagesschau.de/wirtschaft/konjunktur/fruehjahrsgutachten-104.html', '2026-05-27 08:00:58+00', 'Strukturkrise in Deutschland: "Von der Politik im Stich gelassen"', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513066498, '2026-05-27 14:21:20.56514', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Wirtschaftsweisen haben ihre Konjunkturprognose für die deutsche Wirtschaft drastisch nach unten korrigiert. Langfristig dürften auch die steigenden Sozialversicherungsbeiträge das Wachstum bremsen.', 'c358ea2b-e523-4278-87f3-c3ef6682a3bc', 'https://www.tagesschau.de/wirtschaft/konjunktur/sachverstaendigenrat-wirtschaftsweisen-prognose-fruehjahrsgutachten-100.html', '2026-05-27 10:02:41+00', 'Frühjahrsgutachten: Wirtschaftsweise senken Prognose deutlich', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513070592, '2026-05-27 14:21:20.566139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Weltweit feiern Muslime heute Eid al-Adha - das islamische Opferfest. In Marokko kann die Tradition - anders als im vergangenen Jahr - wieder begangen werden. Dank Millionen von Schafen. Von Anne Baier.', '367375dd-32ec-4b34-8970-9a05d65e326f', 'https://www.tagesschau.de/ausland/afrika/islam-opferfest-marokko-100.html', '2026-05-27 07:16:07+00', 'Opferfest in Marokko: Wieder ein Fest des Teilens', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513070593, '2026-05-27 14:21:20.566139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Diesel, lange der günstigere Kraftstoff, kostete zuletzt mehr als Benzin. Inzwischen haben sich die Preise wieder gedreht. Was sind die Gründe? Von Till Bücker.', 'f233cc7f-e7e8-4ec0-9faf-d2df413a6411', 'https://www.tagesschau.de/wirtschaft/verbraucher/spritpreise-diesel-benzin-102.html', '2026-05-27 06:46:25+00', 'Warum Diesel wieder günstiger ist als Benzin', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513070594, '2026-05-27 14:21:20.566139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Kanada ist für Deutschland ein zentraler Partner. Beim Besuch von Verteidigungsminister Pistorius steht ein milliardenschwerer U-Boot-Deal im Vordergrund. Doch Pistorius ist nicht nur als Handelsreisender dort. Von Claudia Buckenmaier.', 'f87c116b-1673-430e-aa99-046ea98c004d', 'https://www.tagesschau.de/inland/innenpolitik/pistorius-reise-kanada-100.html', '2026-05-27 06:45:19+00', 'Wie Pistorius in Kanada ein Milliardengeschäft anstoßen will', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513074688, '2026-05-27 14:21:20.567139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der historische Arbeitskampf beim Elektronikkonzern Samsung ist endgültig abgewendet: Die 48.000 Beschäftigten werden nicht streiken. Denn die Mehrheit stimmte für das Angebot der Geschäftsführung.', '9a7ab89e-3dd0-43ee-b28c-4c9b7c023e17', 'https://www.tagesschau.de/wirtschaft/unternehmen/samsung-einigung-gewerkschaft-streik-100.html', '2026-05-27 06:37:23+00', 'Samsung-Gewerkschaft nimmt Einigung auf Rekordboni an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513074689, '2026-05-27 14:21:20.567139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Für Deutschland ist China Handelspartner Nummer eins. Darum will Wirtschaftsministerin Reiche bei ihrem Besuch in der Volksrepublik die Zusammenarbeit stärken. Aber dafür müssen die Bedingungen stimmen.', 'afefe800-b4ca-48be-82bf-d8c1228e1609', 'https://www.tagesschau.de/wirtschaft/weltwirtschaft/reiche-china-100.html', '2026-05-27 05:42:59+00', 'Wirtschaftsministerin in China - Reiche mahnt fairen Wettbewerb an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513074690, '2026-05-27 14:21:20.567139', 295853820891136, NULL, NULL, '', NULL, NULL, '2019 überrollt nach einem Dammbruch eine Schlammlawine die Gegend um den brasilianischen Ort Brumadinho. Mindestens 270 Menschen sterben. TÜV Süd hatte den Damm als sicher eingestuft. 11KM über die Rolle des deutschen Prüfunternehmens.', 'ace2be94-62db-49ad-a8ad-d76b31d35c17', 'https://www.tagesschau.de/podcast-11km-brasilien-dammbruch-tuev-100.html', '2026-05-27 04:32:52+00', '11KM-Podcast: Dammbruch in Brasilien - Welche Verantwortung trägt TÜV Süd?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513074691, '2026-05-27 14:21:20.567139', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach Deutschland entsenden die in Afghanistan regierenden Taliban bereits Diplomaten. Laut NDR-Recherchen soll das möglichst auch in weiteren EU-Staaten der Fall sein. Als Gegenleistung bieten die Taliban Zusammenarbeit bei Abschiebungen an. Von Peter Hornung.', 'c432d187-c720-48fb-86af-223566a10127', 'https://www.tagesschau.de/investigativ/ndr/taliban-eu-diplomaten-abschiebungen-100.html', '2026-05-27 04:00:48+00', 'Taliban wollen mehr eigene Diplomaten in Europa ', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357745964621824, '2026-05-21 10:49:00.808958', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Leon Ginzel', 'Deutschland', NULL, NULL, 'Die Chefin der Rentenkommission bestätigt einen »Bild«-Bericht nicht. Noch sei nichts entschieden – auch nicht zur Rente mit 70. Erste Reaktionen fallen kritisch aus.', '{urn:uuid:ef07fb43-e5cf-40b6-a6f2-b491ddb7c078}', 'https://www.zeit.de/politik/deutschland/2026-05/diskussion-rente-mit-70-rentenkommission-keine-entscheidung-constanze-janda-reaktionen', '2026-05-21 10:40:21+00', 'Debatte um Rentenreform: Laut Rentenkommission ist »noch keine Empfehlung fertig entschieden«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357745964630016, '2026-05-21 10:49:00.810309', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Alexander Eydlin', 'Wirtschaft', NULL, NULL, 'Statt 1,2 Prozent erwartet die EU-Kommission in diesem Jahr nur noch 0,6 Prozent Wachstum in Deutschland. Das liegt unterhalb des erwarteten Durchschnitts der Eurozone.', '{urn:uuid:04785584-6ee6-45e4-a40f-dd8b93e75994}', 'https://www.zeit.de/wirtschaft/2026-05/eu-kommission-halbiert-wachstumsprognose-fuer-deutschland', '2026-05-21 10:38:51+00', 'Konjunktur: EU-Kommission halbiert Wachstumsprognose für Deutschland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357745964630017, '2026-05-21 10:49:00.810309', 295500424519680, NULL, 'DIE ZEIT: Ausland - Marla  Noss', 'Ausland', NULL, NULL, 'Im Iran sind zwei Männer wegen des Vorwurfs der Mitgliedschaft in einer Terrorgruppe hingerichtet worden. Die NGO Hengaw sprach von kurdischen politischen Gefangenen.', '{urn:uuid:7e654a31-a293-4b3a-a06d-3f1d8fbe456b}', 'https://www.zeit.de/politik/ausland/2026-05/hinrichtungen-iran-maenner-terrorgruppe', '2026-05-21 10:37:30+00', 'Proteste im Iran : Zwei weitere Menschen im Iran hingerichtet', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513074692, '2026-05-27 14:21:20.567139', 295853820891136, NULL, NULL, '', NULL, NULL, 'US-Präsident Trump hat im Streit um Wahlkreiszuschnitte, die seine Republikaner begünstigen, Niederlagen erlitten. In South Carolina blockierten demokratische und republikanische Senatoren eine neue Wahlkreisaufteilung. In Alabama stoppte ein Gericht eine Neuordnung.', '51bf786b-7d56-4706-9b11-4f2b54b3cbd1', 'https://www.tagesschau.de/ausland/amerika/us-wahlkreise-102.html', '2026-05-27 03:02:04+00', 'USA: Doppel-Niederlage für Trump im Streit um Wahlkreiszuschnitte', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513074693, '2026-05-27 14:21:20.567139', 295853820891136, NULL, NULL, '', NULL, NULL, 'In Kongo kämpfen Ärzte und Hilfsorganisationen gegen Ebola - doch es fehlt an Nahrung, Unterkünften und medizinischer Versorgung. Gekürzte Hilfsgelder verschärfen die Lage in einem Gesundheitssystem am Limit. Von Bettina Rühl.', '47c9c670-1030-41ca-9a58-f897b38b7e09', 'https://www.tagesschau.de/ausland/afrika/ebola-hilfsgelder-100.html', '2026-05-27 01:54:17+00', 'Gekürzte Hilfsgelder erschweren Kampf gegen Ebola', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513078784, '2026-05-27 14:21:20.568654', 295853820891136, NULL, NULL, '', NULL, NULL, 'Im US-Bundesstaat Washington ist ein mehrere Millionen Liter fassender Tank mit flüssigen Chemikalien leckgeschlagen. Mindestens eine Person kam ums Leben, weitere Menschen sind verletzt oder werden noch vermisst.', '029b5b12-b908-44d8-a845-3b7081479b11', 'https://www.tagesschau.de/ausland/amerika/tank-washington-100.html', '2026-05-27 05:55:57+00', 'USA: Toter bei Chemie-Unglück in Verpackungsfabrik', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513078785, '2026-05-27 14:21:20.568654', 295853820891136, NULL, NULL, '', NULL, NULL, 'Israel hat den neuen Führer der Hamas im Gazastreifen, Odeh, angegriffen. Bei einem Luftangriff auf Gaza-Stadt seien mehrere Menschen getötet worden - laut Israels Militär auch der neue Chef der Terrororganisation.', '35bcad8b-237b-4cb8-9c34-897c54d6098d', 'https://www.tagesschau.de/ausland/asien/israel-toetet-hamas-fuehrer-100.html', '2026-05-27 06:35:23+00', 'Neuer Hamas-Chef im Gazastreifen getötet', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513082880, '2026-05-27 14:21:20.56923', 295853820891136, NULL, NULL, '', NULL, NULL, 'Eine Hitzewelle hat weite Teile Westeuropas im Griff. Anders als Frankreich und Großbritannien gab es in Deutschland aber bislang keinen Temperaturrekord für den Monat Mai. In Regensburg war es mit 34 Grad am wärmsten.', 'b3bfbeb9-ca90-4412-af94-cb4c4f5aab17', 'https://www.tagesschau.de/wetter/deutschland/wetter-mai-temperaturen-100.html', '2026-05-26 20:59:02+00', 'Hitzewelle in Deutschland: Vielerorts über 30 Grad, aber noch kein Mai-Rekord', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513082881, '2026-05-27 14:21:20.56923', 295853820891136, NULL, NULL, '', NULL, NULL, 'Russland verschärft seine Rhetorik: Der Kreml kündigt weitere massive Angriffe auf Kiew an. Silke Diettrich, Moskau-Korrespondentin der ARD sagt, solche Drohungen müsse man ernst nehmen. Russland wolle nun ein Zeichen der Stärke setzen.', '8a3e3fad-dedf-4c09-b194-9967d2af8f56', 'https://www.tagesschau.de/ausland/europa/ukraine-diettrich-100.html', '2026-05-26 19:14:16+00', 'Einschätzungen von ARD-Korrespondentin Diettrich zu den russischen Drohungen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513082882, '2026-05-27 14:21:20.56923', 295853820891136, NULL, NULL, '', NULL, NULL, 'Israel hat die angekündigte neue Offensive gegen die Hisbollah-Miliz im Libanon begonnen. Medienberichten zufolge auch mit Bodentruppen nördlich des Litani-Flusses. Libanesische Behörden melden mehr als 30 Tote durch israelische Angriffe.', '16b3cecc-2a57-4d15-8def-076c60750b22', 'https://www.tagesschau.de/ausland/asien/israel-angriffe-libanon-126.html', '2026-05-27 08:35:35+00', 'Israel weitet Bodeneinsätze gegen Hisbollah im Libanon aus', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357747219304448, '2026-05-21 10:54:07.127165', 295500424519680, NULL, 'DIE ZEIT: Sport - Maxim Nägele', 'Sport', NULL, NULL, 'Vier deutsche Großstädte und Regionen planen derzeit, die Olympischen Spiele auszurichten. Das Berliner Abgeordnetenhaus hat für eine Bewerbung der Hauptstadt gestimmt.', '{urn:uuid:6d96da9e-b172-4064-87b8-121a4646518c}', 'https://www.zeit.de/sport/2026-05/berlin-olympia-bewerbung-abstimmung-abgeordnetenhaus-mehrheit', '2026-05-21 10:48:39+00', 'Olympia-Bewerbung: Berliner Abgeordnetenhaus stimmt für Olympia-Bewerbung', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513082883, '2026-05-27 14:21:20.56923', 295853820891136, NULL, NULL, '', NULL, NULL, 'Radikal fünf Prozent kürzen - bei allen Subventionen, so der Vorschlag von Unionsfraktionschef Spahn. Neu ist die Idee nicht. Bereits 2003 warfen Steinbrück und Koch den "Rasenmäher" an. Auch heute sehen sie Sparpotenzial. Von G. Schwarte.', 'b276ccda-777d-41e6-a06b-de9240aea3aa', 'https://www.tagesschau.de/inland/innenpolitik/rasenmaeher-kuerzungen-koch-steinbrueck-100.html', '2026-05-26 18:03:25+00', 'Einmal "Rasenmäher" à la Koch und Steinbrück?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513086976, '2026-05-27 14:21:20.570382', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach der Absetzung des türkischen Oppositionsführers Özel gibt es weiter Proteste. Obwohl die Polizei gegen ihn und seine Anhänger vorgeht, könnte der Ex-CHP-Chef für die Regierung Erdoğan gefährlich bleiben. Von B. Weber.', 'd7fea527-5237-44b0-b9de-0e4407920a71', 'https://www.tagesschau.de/ausland/asien/izmir-proteste-chp-100.html', '2026-05-26 17:31:52+00', 'Türkei: Polizei geht hart gegen Özel und seine Anhänger vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513086977, '2026-05-27 14:21:20.570382', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Kreml droht ausländischen Botschaften in Kiew. In der Ukraine sehen viele darin lediglich einen Versuch, Panik auszulösen. Dennoch bleibt die Angst, Diplomaten könnten das Land verlassen. Von F. Kellermann.', '2c165629-7e1c-4392-a192-502c6f3d9825', 'https://www.tagesschau.de/ausland/europa/ukraine-russland-drohungen-diplomaten-100.html', '2026-05-26 16:17:11+00', 'Ukraine beruhigt Bürger und Diplomaten nach Putin-Drohung', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513086978, '2026-05-27 14:21:20.570382', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ein echter Durchbruch in den Friedensverhandlungen am Persischen Golf lässt weiter auf sich warten. Der DAX gab einen Teil seiner jüngsten Gewinne ab, während die Ölpreise wieder anzogen.', '45c8c90d-c2d4-42b0-b4f9-2509ee8a5105', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-dow-jones-euro-dollar-104.html', '2026-05-26 16:12:00+00', 'Marktbericht: Anleger verlieren die Geduld', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513086979, '2026-05-27 14:21:20.570382', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Bretagne ist nicht die heißeste Gegend Frankreichs - doch selbst hier gibt es jetzt Temperaturen von weit über 30 Grad. Das Land erlebt eine historische Hitzewelle - mit massiven Risiken. Von Cai Rienäcker.', '243ab0f9-5bd1-49d5-bc02-4a15d4eb45fa', 'https://www.tagesschau.de/ausland/europa/frankreich-hitze-112.html', '2026-05-26 16:09:50+00', 'Rekordtemperaturen in Frankreich mit sieben Toten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513091072, '2026-05-27 14:21:20.571391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach dem schweren Zusammenstoß zwischen einem Schulbus und einem Zug in Belgien haben die Untersuchungen begonnen. Offenbar hat der Bus die Schranke am Bahnübergang durchbrochen. Von Kathrin Schmid.', '4b29256c-7b17-46de-a72c-684ec3a55a68', 'https://www.tagesschau.de/ausland/europa/belgien-zugunglueck-schulbus-100.html', '2026-05-26 15:37:53+00', 'Belgien: Ermittlungen nach Zugunglück laufen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513091073, '2026-05-27 14:21:20.571391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Pflegeversicherung droht ein Milliardenloch. Gesundheitsministerin Warken will gegensteuern und erwägt offenbar höhere Beiträge für Kinderlose. Zustimmung kommt von SPD und CSU. Aber es gibt auch Kritik.', 'c38a486c-71e5-4d9c-a0e5-d5e64f1cb961', 'https://www.tagesschau.de/inland/innenpolitik/warken-pflegeversicherung-100.html', '2026-05-26 15:37:31+00', 'Kritik an Warken-Plänen zu höheren Pflegebeiträgen für Kinderlose', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513091074, '2026-05-27 14:21:20.571391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Bundesregierung hat den russischen Botschafter einbestellt. Grund sind die jüngsten russischen Angriffe auf Kiew sowie Drohungen gegen dortige ausländische Botschaften und Organisationen. Auch die EU bestellte einen russischen Diplomaten ein.', '028bb1e4-9d1f-45c6-9331-50fc9c3d2990', 'https://www.tagesschau.de/ausland/ukraine-russland-eu-102.html', '2026-05-26 14:52:58+00', 'Krieg gegen die Ukraine: Bundesregierung bestellt russischen Botschafter ein', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513091075, '2026-05-27 14:21:20.571391', 295853820891136, NULL, NULL, '', NULL, NULL, 'In Großbritannien hat es auch heute wieder einen Mai-Hitzerekord gegeben. Während sich viele Briten über die Temperaturen freuen und die Strände voll sind, sorgen sich Experten. Von Franziska Hoppen.', 'c8cd8c58-145a-4765-a235-5727b3887b31', 'https://www.tagesschau.de/ausland/europa/england-hitze-welle-100.html', '2026-05-26 14:20:23+00', 'Hitzewelle in Großbritannien: Nationaler Wetterdienst warnt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513091076, '2026-05-27 14:21:20.571391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Es sind Verhandlungen mit vielen offenen Fragen: Die Knackpunkte im Konflikt zwischen den USA und Iran sind nur schwer lösbar. Und die neuen Angriffe des US-Militärs auf Iran könnten ein weiteres Hindernis sein.', 'fe7af7ee-b532-41f8-a699-46d0b4fa486e', 'https://www.tagesschau.de/ausland/asien/iran-usa-konflikt-verhandlungen-waffenruhe-100.html', '2026-05-26 13:44:11+00', 'Viele offene Fragen bei Verhandlungen zwischen USA und Iran', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513918464, '2026-05-27 14:21:20.773811', 295514619002880, NULL, NULL, '', NULL, NULL, 'Solar and wind produce lots of energy — but not always at the right time. More battery storage could help Europe to stabilize prices and replace polluting fossil fuel energy, but roadblocks remain.', NULL, 'https://www.dw.com/en/europe-s-energy-problem-isn-t-green-power-it-s-storage/a-77302218?maca=en-rss-en-all-1573-rdf', '2026-05-27 13:43:00+00', 'Europe''s energy problem isn''t green power — it''s storage', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513922560, '2026-05-27 14:21:20.774813', 295514619002880, NULL, NULL, '', NULL, NULL, 'The war in the Middle East is threatening fossil fuel supplies and leading fuel and gas prices to rise in Germany. Could that drive a surge in demand for heat pumps?', NULL, 'https://www.dw.com/en/germany-hopes-for-heat-pump-boom-amid-iran-war/a-77310083?maca=en-rss-en-all-1573-rdf', '2026-05-27 13:11:00+00', 'Germany hopes for heat pump boom amid Iran war', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549087744, '2026-05-21 12:16:50.453006', 295500424519680, NULL, 'DIE ZEIT: Ausland - Alexander Eydlin', 'Ausland', NULL, NULL, 'Ungarns neuer Regierungschef verspricht in Österreich fairen Wettbewerb für Investoren. Seinem Vorgänger Viktor Orbán wirft er vor, Wirtschaftsdaten geschönt zu haben.', '{urn:uuid:5394a5ad-4d03-42da-aa44-3e99afda06f5}', 'https://www.zeit.de/politik/ausland/2026-05/ungarn-peter-magyar-oesterreich-eu-viktor-orban', '2026-05-21 12:06:32+00', 'Ungarn: Péter Magyar will Ungarn attraktiver für EU-Investitionen machen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549087745, '2026-05-21 12:16:50.453006', 295500424519680, NULL, 'DIE ZEIT: Gesellschaft - Jochen Wegner, Christoph Amend', 'Gesellschaft', NULL, NULL, 'Sie sind das bekannteste muslimisch-jüdische Ehepaar Deutschlands. Im Podcast sprechen sie über ihre Herkunft und ihren Kampf gegen Antisemitismus und Islamfeindlichkeit.', '{urn:uuid:d78ca32f-1b22-4873-bc2f-6de4c6f789d0}', 'https://www.zeit.de/gesellschaft/2026-05/cheema-mendel-interviewpodcast-alles-gesagt', '2026-05-21 11:50:27+00', 'Saba-Nur Cheema und Meron Mendel: Saba-Nur Cheema & Meron Mendel, wie geht jüdisch-muslimischer Dialog?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549087746, '2026-05-21 12:16:50.453006', 295500424519680, NULL, 'DIE ZEIT: Politik - Florian Eichel, Tilman Leicht', 'Politik', NULL, NULL, 'Obwohl Drohnen den Ukrainekrieg dominieren, beschafft die Bundeswehr vor allem Panzer. Rüsten wir uns für den falschen Krieg? Nein, sagt der Experte Lawrence Freedman.', '{urn:uuid:ed26cb63-6241-4b4e-bcbe-3556f1aae0ed}', 'https://www.zeit.de/politik/2026-05/aufruestung-bundeswehr-drohnen-panzer-ki-lawrence-freedman', '2026-05-21 11:48:45+00', 'Aufrüstung: »Weder Panzer noch Drohnen entscheiden Kriege, sondern Menschen«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549091840, '2026-05-21 12:16:50.454005', 295500424519680, NULL, 'DIE ZEIT: Sport - Yannick von Eisenhart Rothe, Sophia Reddig, Leon Ginzel', 'Sport', NULL, NULL, 'Die Rückkehr des eigentlich zurückgetretenen Torhüters Manuel Neuer in die Nationalmannschaft ist perfekt. Er gehört zum deutschen Kader für die WM. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-05-21 11:44:13+00', 'Fußballweltmeisterschaft 2026: Manuel Neuer steht als Nummer eins im WM-Kader', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549091841, '2026-05-21 12:16:50.454005', 295500424519680, NULL, 'DIE ZEIT: Ausland - Simone Brunner', 'Ausland', NULL, NULL, 'Er soll Daten an Moskau verkauft haben. Jetzt wurde Egisto Ott verurteilt: vier Jahre Haft. Er wird gegen das Urteil vorgehen.', '{urn:uuid:633fccbe-4c23-4f13-938e-6bb5f4bb0494}', 'https://www.zeit.de/politik/ausland/2026-05/prozess-egisto-ott-spionage-verfassungsschutz-wien', '2026-05-21 11:27:54+00', 'Prozess gegen Egisto Ott: »Ich bin ein Spion«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549091842, '2026-05-21 12:16:50.454005', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Leon Ginzel', 'Deutschland', NULL, NULL, 'Die Chefin der Rentenkommission bestätigt einen »Bild«-Bericht nicht. Noch sei nichts entschieden – auch nicht zur Rente mit 70. Erste Reaktionen fallen kritisch aus.', '{urn:uuid:ef07fb43-e5cf-40b6-a6f2-b491ddb7c078}', 'https://www.zeit.de/politik/deutschland/2026-05/diskussion-rente-mit-70-rentenkommission-keine-entscheidung-constanze-janda-reaktionen-gxe', '2026-05-21 11:17:01+00', 'Debatte um Rentenreform: Laut Rentenkommission ist »noch keine Empfehlung fertig entschieden«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549091843, '2026-05-21 12:16:50.454005', 295500424519680, NULL, 'DIE ZEIT: Sport - Maxim Nägele', 'Sport', NULL, NULL, 'Vier deutsche Großstädte und Regionen planen derzeit, die Olympischen Spiele auszurichten. Das Berliner Abgeordnetenhaus hat für eine Bewerbung der Hauptstadt gestimmt.', '{urn:uuid:6d96da9e-b172-4064-87b8-121a4646518c}', 'https://www.zeit.de/sport/2026-05/berlin-olympia-bewerbung-abstimmung-abgeordnetenhaus-mehrheit-gxe', '2026-05-21 11:15:56+00', 'Olympia-Bewerbung: Berliner Abgeordnetenhaus stimmt für Olympia-Bewerbung', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549677568, '2026-05-21 12:16:50.598028', 295853820891136, NULL, NULL, '', NULL, NULL, 'Wegen der wirtschaftlichen Folgen des Iran-Kriegs hat die EU-Kommission ihre Wachstumsvorhersage für Deutschland deutlich gesenkt. Leichte Besserung ist Experten zufolge erst 2027 in Sicht - aber nur unter Bedingungen.', 'a9ac78a7-6a44-45ce-8d71-c71351b2d5bf', 'https://www.tagesschau.de/wirtschaft/eu-konjunktur-prognose-deutschland-100.html', '2026-05-21 11:15:49+00', 'EU-Kommission senkt Wachstumsprognose für Deutschland deutlich', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549681664, '2026-05-21 12:16:50.598028', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bundestrainer Nagelsmann hat den WM-Kader vorgestellt - 26 Spieler sind dabei. Und im Tor wird wieder Manuel Neuer stehen. Er kehrt zwei Jahre nach seinem Rücktritt in die Nationalmannschaft zurück - als Nummer eins.', '426e04bc-e26c-4f19-938d-22bfe9f15561', 'https://www.tagesschau.de/sport/wm-kader-neuer-100.html', '2026-05-21 11:39:37+00', 'WM-Kader bekannt gegeben: Neuer kehrt in Nationalelf zurück', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549681665, '2026-05-21 12:16:50.598028', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Generalbundesanwalt hat zwei Männer angeklagt: Sie sollen im Auftrag der iranischen Revolutionsgarde einen Anschlag in Berlin geplant haben. Die Sorge vor Angriffen auf jüdische Einrichtungen bleibt groß. Von M. Götschenberg und H. Schmidt.', '22d46fcf-b2b3-4369-86a2-3a94050db7bf', 'https://www.tagesschau.de/inland/gesellschaft/anklage-anschlag-iran-deutschland-100.html', '2026-05-21 10:59:38+00', 'Anklage: Anschlag in Berlin im Auftrag der Revolutionsgarde geplant? ', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357767549681666, '2026-05-21 12:16:50.598028', 295853820891136, NULL, NULL, '', NULL, NULL, 'Fest steht: Das Rentensystem soll reformiert werden. Ein Medienbericht über höheres Eintrittsalter wird zwar entschieden dementiert. Trotzdem gibt es eine Diskussion über das Für und Wider.', '80d5f847-8c65-432e-8441-e313b5cee47f', 'https://www.tagesschau.de/inland/innenpolitik/debatte-rente-renteneintrittsalter-100.html', '2026-05-21 10:58:14+00', 'Dementierter Medienbericht: Mögliche Rente mit 70 sorgt für Diskussion', NULL);
