INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921513959425, '2026-05-27 14:21:20.783399', 295514619002880, NULL, NULL, '', NULL, NULL, 'A Turkish court has allowed DW reporter Alican Uludag to leave detention as his contentious trial opens. He is accused of having "insulted" President Recep Tayyip Erdogan, which in Turkey can carry a jail sentence.', NULL, 'https://www.dw.com/en/turkey-dw-s-alican-uludag-released-but-trial-continues/a-77247916?maca=en-rss-en-all-1573-rdf', '2026-05-21 13:45:00+00', 'Turkey: DW''s Alican Uludag released, but trial continues', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921514983424, '2026-05-27 14:21:21.033915', 295880188006400, NULL, NULL, '', NULL, NULL, 'Auf den Straßen der Ukraine spielen die Kinder Krieg, während um sie herum der reale Krieg tobt. Der Dokumentarfilm fängt den Kriegsalltag und dessen Auswirkungen auf das Leben der Menschen aus unmittelbarer Nähe ein. Neben den Kindern rückt dabei die Beziehung eines Mannes, der an der Front kämpft, und seiner Frau, die mit den gemeinsamen Kindern nach Kanada geflohen ist, in den Mittelpunkt. Insgesamt entsteht ein durchaus eindrucksvolles Stimmungsbild, das jedoch einen roten Faden vermissen lässt und bisweilen sowohl durch seinen dramaturgischen Aufbau als auch durch seine Distanzlosigkeit irritiert.', 'https://www.filmdienst.de/film/details/626332/in-case-we-never-meet-again', 'https://www.filmdienst.de/film/details/626332/in-case-we-never-meet-again', '2026-05-26 07:41:54+00', 'In Case We Never Meet Again', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921514983425, '2026-05-27 14:21:21.033915', 295880188006400, NULL, NULL, '', NULL, NULL, 'Der 1971 geborene Schotte John Davidson leidet von Kindheit an unter einer besonders schweren Form des Tourette-Syndroms, die zu körperlichen Ausfällen und ungewollten verbalen Entgleisungen führt. Lange stieß er in der Familie und in seinem Umfeld auf Unverständnis, wurde ausgegrenzt und verprügelt. Erst als eine befreundete Krankenschwester ihm zu helfen begann, ging es aufwärts, und es stellten sich Erfahrungen von Akzeptanz ein. Eine Filmbiografie über einen der bekanntesten Tourette-Aufklärer, inszeniert als mitreißende, anrührende und warmherzige Tragikomödie. Glaubwürdig und unsentimental sensibilisiert der Film für ein Leben mit Tourette-Syndrom, unterstützt von diskreter Kameraarbeit, unaufdringlicher Musik und einem ausgezeichneten Ensemble.', 'https://www.filmdienst.de/film/details/626213/verflucht-normal', 'https://www.filmdienst.de/film/details/626213/verflucht-normal', '2026-05-27 09:22:22+00', 'Verflucht Normal', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921514987520, '2026-05-27 14:21:21.034915', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein junges Paar gibt seine Wohnung in New York auf, um fortan in einem zum Camper umgebauten Transporter durch das Land zu reisen. Als sie eines Nachts fast von der Fahrbahn gedrängt werden und im Zuge dessen einen folgenschweren Autounfall beobachten, eilen sie dem Verunglückten zur Hilfe. Fortan werden sie von einer unheimlichen Präsenz begleitet, deren Geheimnis sie durch Hinweise einer Nomadin und über eine alte Saga zu lüften hoffen. Der Horrorfilm nimmt sich des uramerikanischen Mythos des Pilgertums an und erzählt seine Geister-Geschichte als düsteres Road Movie. Einige atmosphärische Schauerszenen und die kreativen visuellen Ideen können allerdings nicht alle Leerstellen füllen, auch weil die Protagonisten zu glatt bleiben.', 'https://www.filmdienst.de/film/details/626210/passenger', 'https://www.filmdienst.de/film/details/626210/passenger', '2026-05-26 14:37:25+00', 'Passenger', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921514987521, '2026-05-27 14:21:21.034915', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein alternder Sänger mit gesundheitlichen Problemen reist in die Schweiz, wo er sein Leben durch assistierten Suizid beenden lassen will. Auf der Fahrt wird er im Zug von einer redseligen Frau in Beschlag genommen, die ihm auch nach der Ankunft weiter an seine Fersen heftet. Als sie hinter sein Geheimnis kommt, setzt sie alles daran, sein Vorhaben zu verhindern. Klassische Romantikkomödien-Strukturen verbinden sich in dem Film mit dem Ernst von Themen wie Krankheit und Einsamkeit zu einer überzeugenden Mischung. Neben unterhaltsamem Wortwitz und Slapstick setzt er auf eine lebensbejahende Grundhaltung, die auch für anrührende Momente sorgt.', 'https://www.filmdienst.de/film/details/626021/ticket-ins-leben', 'https://www.filmdienst.de/film/details/626021/ticket-ins-leben', '2026-05-27 07:00:48+00', 'Ticket ins Leben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921514987522, '2026-05-27 14:21:21.034915', 295880188006400, NULL, NULL, '', NULL, NULL, 'Der TV-Journalist Michael Born (1958-2019) hat in den 1990er-Jahren zahlreiche erfundene Reportagen fürs Privatfernsehen gedreht, was erst nach Jahren auffiel. Mit Archivmaterial sowie Gesprächen mit Freunden, ehemaligen Kollegen und einer Medienwissenschaftlerin zeichnet der Dokumentarfilm Borns Werdegang nach und porträtiert ihn teils als anarchischen Schelm, teils als zerrissenen Idealisten, der mit seinen dilettantischen Fälschungen indirekt ein auf Sensationslust ausgerichtetes Fernsehen vorgeführt hat. Auf einer analytischen Ebene widmet sich der Film zudem dem fragwürdigen Wahrheitsgehalt dokumentarischer Bilder. Auch wenn er seinen zahlreichen Themen nicht immer gerecht wird, widmet er sich doch über weite Strecken anekdotenreich und amüsant einem verblüffenden Kuriosum der TV-Geschichte.', 'https://www.filmdienst.de/film/details/624895/born-to-fake', 'https://www.filmdienst.de/film/details/624895/born-to-fake', '2026-05-27 12:15:24+00', 'Born to Fake', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921515663360, '2026-05-27 14:21:21.199549', 297940250853376, NULL, NULL, '', NULL, NULL, 'Rund 18 Kilo Kleidung kauft jede und jeder Deutsche im Schnitt pro Jahr. Zugleich landen pro Kopf jährlich 16 Kilo Altkleider im Müll. Fast Fashion treibt diese Entwicklung an. Sie schadet damit der Umwelt. Die EU will dem Einhalt gebieten. Von Alexander Böhle', 'fast-fashion-mode-eu-regulierung-nachhaltigkeit-100', 'https://www.deutschlandfunk.de/fast-fashion-mode-eu-regulierung-nachhaltigkeit-100.html', '2026-05-25 15:00:00+00', 'Fast Fashion - Wie die EU die schnelle Billigmode nachhaltiger machen will', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921515667456, '2026-05-27 14:21:21.200555', 297940250853376, NULL, NULL, '', NULL, NULL, 'Die Bundeswehr investiert Milliarden in neue Waffen und Ausrüstung. Davon profitiert besonders Rheinmetall: Der Konzern könnte sich zum zentralen Ausrüster der Truppe entwickeln. Das verspricht Effizienz – birgt aber auch Risiken.', 'ruestungskonzern-rheinmetall-aufruestung-verteidigung-100', 'https://www.deutschlandfunk.de/ruestungskonzern-rheinmetall-aufruestung-verteidigung-100.html', '2026-05-25 14:43:00+00', 'Verteidigung - Wird Rheinmetall zum Rüstungsriesen der Bundeswehr?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921515667457, '2026-05-27 14:21:21.200555', 297940250853376, NULL, NULL, '', NULL, NULL, 'Flüge könnten bald deutlich teurer werden. Grund ist der drohende Kerosinmangel durch den Irankrieg. Aber dürfen Reiseveranstalter auch für bereits gebuchte Reisen Nachzahlungen verlangen?', 'urlaub-fluege-teurer-kerosin-preis-reisen-100', 'https://www.deutschlandfunk.de/urlaub-fluege-teurer-kerosin-preis-reisen-100.html', '2026-05-24 14:01:00+00', 'Flüge - Plötzlich kostet der gebuchte Urlaub mehr – Ist das erlaubt?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921515667458, '2026-05-27 14:21:21.200555', 297940250853376, NULL, NULL, '', NULL, NULL, 'Die deutsche Offshore-Windbranche steckt in der Krise. Ausgerechnet zwei Ölkonzerne gehören zu den wichtigsten Akteuren auf dem Markt. Wie abhängig ist die Energiewende von solchen fossilen Unternehmen? Von Philipp Lemmerich', 'offshore-windanlagen-energiewende-oelkonzerne-100', 'https://www.deutschlandfunk.de/offshore-windanlagen-energiewende-oelkonzerne-100.html', '2026-05-22 15:37:00+00', 'Offshore-Windenergie - Welche Rolle spielen fossile Konzerne bei der Energiewende?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921515667459, '2026-05-27 14:21:21.200555', 297940250853376, NULL, NULL, '', NULL, NULL, 'In Deutschland mangelt es an bezahlbarem Wohnraum. Einige Experten sehen dafür strukturelle und hausgemachte Gründe. Der Staat müsse wieder mehr Wohnraum schaffen. Bedürftige Mieter zu unterstützen, könne das Problem hingegen langfristig verschärfen.', 'wohnungsmangel-wohngeld-sozialwohnungen-mieten-100', 'https://www.deutschlandfunk.de/wohnungsmangel-wohngeld-sozialwohnungen-mieten-100.html', '2026-05-22 09:33:00+00', 'Hohe Mieten - Verschärft Wohngeld die Wohnungskrise?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516036096, '2026-05-27 14:21:21.290355', 297942154895360, NULL, NULL, '', NULL, NULL, 'Mit den hohen Temperaturen beginnt jedes Jahr nicht nur die Badesaison, sondern auch die Saison der Stechmücken. Die Insekten sind allerdings nicht nur lästig. Sie verbreiten in Europa zunehmend auch gefährliche Krankheiten wie das Dengue-Fieber.', 'muecken-krankheiten-west-nil-dengue-chikungunya-fieber-klimawandel-100', 'https://www.deutschlandfunk.de/muecken-krankheiten-west-nil-dengue-chikungunya-fieber-klimawandel-100.html', '2026-05-27 14:14:00+00', 'Tropische Krankheiten in Europa - Warum Stechmücken gefährlicher werden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516036097, '2026-05-27 14:21:21.290355', 297942154895360, NULL, NULL, '', NULL, NULL, 'Der Weltklimarat hat das bisherige Worst-Case-Szenario für die Erderwärmung nach unten korrigiert. Einige Akteure erklären daraufhin den Klimawandel für abgesagt. Dafür gibt es jedoch keinen Anlass: Auch das realistischere Szenario ist drastisch genug. Büüsker, Ann-Kathrin', 'klimawandel-verharmlosung-warum-gerade-eine-desinformationswelle-losrollt-100', 'https://www.deutschlandfunk.de/klimawandel-verharmlosung-warum-gerade-eine-desinformationswelle-losrollt-100.html', '2026-05-27 09:36:00+00', 'Klimaforschung - Der Klimawandel ist nicht abgesagt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516040192, '2026-05-27 14:21:21.291364', 297942154895360, NULL, NULL, '', NULL, NULL, 'Heute Abend leuchtet der zunehmende Mond nahe dem Stern Spica in der Jungfrau. Noch ist offen, wann wieder Menschen über die Mondoberfläche laufen. Der Traum vom Mond ist keine moderne Erscheinung – es gab ihn schon in der Antike. Lorenzen, Dirk', 'sternzeit-27-mai-2026-der-antike-flug-zum-mond-100', 'https://www.deutschlandfunk.de/sternzeit-27-mai-2026-der-antike-flug-zum-mond-100.html', '2026-05-27 00:57:05+00', 'Lukianos - Der antike Flug zum Mond', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357768787595264, '2026-05-21 12:21:52.82368', 295500424519680, NULL, 'DIE ZEIT: Sport - Maxim Nägele', 'Sport', NULL, NULL, 'Drei Wochen vor der Fußball-WM präsentiert Bundestrainer Nagelsmann den deutschen Kader. Mit dabei ist Weltmeister Neuer, El Mala fehlt überraschend.', '{urn:uuid:7fb98a7c-3a7a-405d-aca0-4925db79debd}', 'https://www.zeit.de/sport/2026-05/fussball-wm-kader-nagelsmann-neuer', '2026-05-21 12:18:15+00', 'Fußballweltmeisterschaft 2026: Julian Nagelsmann stellt Kader für die WM vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516040193, '2026-05-27 14:21:21.291364', 297942154895360, NULL, NULL, '', NULL, NULL, 'Ob Geldbuße oder Gefängnis: Strafen sollen abschreckend wirken. Doch harte Bestrafung kann unter Umständen sogar das Gegenteil bewirken. Welche Alternativen gibt es? Und muss Strafe überhaupt sein? Von Johanna Bentz', 'strafe-justiz-gefaengnis-resozialisierung-recht-taeter-opfer-100', 'https://www.deutschlandfunk.de/strafe-justiz-gefaengnis-resozialisierung-recht-taeter-opfer-100.html', '2026-05-26 09:24:00+00', 'Justiz - Muss Strafe sein?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516040194, '2026-05-27 14:21:21.291364', 297942154895360, NULL, NULL, '', NULL, NULL, 'Sally Ride wäre beinahe professionelle Tennisspielerin geworden. Sie entschied sich dann doch für die Astrophysik – und wurde die erste US-Bürgerin im Weltall. Ihre Lebensaufgabe war, Schülerinnen und Schüler für Wissenschaft und Technik zu begeistern. Lorenzen, Dirk', 'sally-ride-astronautin-100', 'https://www.deutschlandfunk.de/sally-ride-astronautin-100.html', '2026-05-26 00:57:57+00', 'Raumfahrt-Pionierin - Sally Ride, die Astrophysikerin-Astronautin', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516040195, '2026-05-27 14:21:21.291364', 297942154895360, NULL, NULL, '', NULL, NULL, '„Diese Nation sollte sich dem Ziel verschreiben, bis zum Ende des Jahrzehnts Menschen auf den Mond und wieder sicher zurück zur Erde zu bringen.“ Vor 65 Jahren leitete US-Präsident Kennedy das Apollo-Projekt ein. Es wurde ebenso teuer wie erfolgreich. Lorenzen, Dirk', 'sternzeit-25-mai-2026-kennedy-und-das-jahrzehnt-des-aufbruchs-zum-mond-100', 'https://www.deutschlandfunk.de/sternzeit-25-mai-2026-kennedy-und-das-jahrzehnt-des-aufbruchs-zum-mond-100.html', '2026-05-25 00:05:58+00', 'Legendäre Rede - Kennedy und das Jahrzehnt des Aufbruchs zum Mond', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516040196, '2026-05-27 14:21:21.291364', 297942154895360, NULL, NULL, '', NULL, NULL, 'In zwei Jahren soll in Namibia ein Radioteleskop mit 14 Metern Durchmesser in Betrieb gehen. Das Africa Millimeter Telescope wird das Universum vor allem im Bereich der Millimeter-Strahlung beobachten – und etwa Schwarze Löcher anpeilen. Lorenzen, Dirk', 'africa-millimeter-telescope-namibia-schwarzes-loch-100', 'https://www.deutschlandfunk.de/africa-millimeter-telescope-namibia-schwarzes-loch-100.html', '2026-05-24 00:05:02+00', 'Erfolg für Afrika - Ein Schwarzes-Loch-Teleskop für Namibia', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516044288, '2026-05-27 14:21:21.292361', 297942154895360, NULL, NULL, '', NULL, NULL, 'Immer wieder schlagen kosmische Brocken auf der Erde ein. Anfang März sorgte ein tennisballgroßer Meteorit für Aufsehen, der ein Hausdach in Koblenz getroffen hatte. Zuvor war er für einige Sekunden als glühendes Objekt über den Himmel gezogen. Lorenzen, Dirk', 'meteoroid-meteor-meteorit-unterschied-100', 'https://www.deutschlandfunk.de/meteoroid-meteor-meteorit-unterschied-100.html', '2026-05-23 00:05:21+00', 'Brocken aus dem All - Erst Meteoroid, dann Meteor, dann Meteorit', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516044289, '2026-05-27 14:21:21.292361', 297942154895360, NULL, NULL, '', NULL, NULL, 'Am Abend steht der schon fast halb beleuchtete Mond am Südwesthimmel. Der dunkle Fleck mitten an der Licht-Schatten-Grenze ist das Meer der Ruhe. Dort haben die ersten Menschen den Mond betreten. Vielleicht besuchen bald Touristen die Landestelle. Lorenzen, Dirk', 'neil-armstrong-mond-fussabdruck-100', 'https://www.deutschlandfunk.de/neil-armstrong-mond-fussabdruck-100.html', '2026-05-22 00:57:12+00', 'Bald zertrampelt? - Armstrongs letzte Spuren auf dem Mond', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359921516044290, '2026-05-27 14:21:21.292361', 297942154895360, NULL, NULL, '', NULL, NULL, 'Gegen die aktuelle Variante des Ebolavirus gibt es bislang keinen Impfstoff. Das soll sich ändern. Zukünftige Impfungen sollten aber auch gegen andere Filoviren wirken, so Clara Schoeder vom Institut für Wirkstoffentwicklung der Universität Leipzig. Brose, Maximilian', 'ebola-ausbruch-impfstoff-gegen-zaire-bundibugyo-und-marburg-wird-erforscht-100', 'https://www.deutschlandfunk.de/ebola-ausbruch-impfstoff-gegen-zaire-bundibugyo-und-marburg-wird-erforscht-100.html', '2026-05-21 14:41:11+00', 'Ebola-Ausbruch - Auf der Suche nach dem Impfstoff', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359924999389184, '2026-05-27 14:35:31.718386', 295500424519680, NULL, 'DIE ZEIT: Politik - Judith Raupp', 'Politik', NULL, NULL, 'Unsere Autorin lebt seit 15 Jahren im Ostkongo, wo Ebola wieder ausgebrochen ist. Die Menschen haben Angst um ihr Leben. Nicht nur wegen des Virus.', '{urn:uuid:00851769-8a05-4699-9059-25588f811ece}', 'https://www.zeit.de/politik/2026-05/ebola-ausbruch-kongo-goma-virus-angst', '2026-05-27 14:31:21+00', 'Ebola-Ausbruch im Kongo: Die Kinder essen einmal am Tag, die Erwachsenen jeden zweiten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359924999389185, '2026-05-27 14:35:31.718386', 295500424519680, NULL, 'DIE ZEIT: Ausland - David Rech, Gregor Aisch', 'Ausland', NULL, NULL, 'Auf extreme Art und Weise schneiden sich Republikaner und Demokraten ihre Wahlkreise zurecht. Ein Supreme-Court-Urteil verschafft den Konservativen dabei einen Vorteil.', '{urn:uuid:3d9ae2a2-f2df-4254-b2be-1411a8fa53db}', 'https://www.zeit.de/politik/ausland/2026-05/gerrymandering-midterms-usa-zwischenwahlen-repraesentantenhaus', '2026-05-27 14:20:34+00', 'Gerrymandering vor den Midterms: Der Kampf um die US-Wahlkreise', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359924999868416, '2026-05-27 14:35:31.83526', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die deutsche Luft- und Raumfahrtbranche verzeichnet so hohe Umsätze wie noch nie. Und auch die Mitarbeiterzahl klettert auf einen Höchststand. Hintergrund sind deutlich mehr Rüstungsaufträge.', 'd471c5cd-a3fc-4633-8086-cfbfd3ad792d', 'https://www.tagesschau.de/wirtschaft/unternehmen/luftfahrt-raumfahrt-industrie-ruestung-100.html', '2026-05-27 14:25:49+00', 'Rüstungsboom beschert deutscher Luft- und Raumfahrt Rekorde', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359925000429568, '2026-05-27 14:35:31.972181', 295514619002880, NULL, NULL, '', NULL, NULL, 'The fragile logistics corridor via Gulf states that connects African patients with critical Indian pharmaceuticals has been thrown into disarray with the Strait of Hormuz closed.', NULL, 'https://www.dw.com/en/india-s-drug-lifeline-to-africa-disrupted-by-iran-war/a-77318563?maca=en-rss-en-all-1573-rdf', '2026-05-27 14:22:00+00', 'India''s drug lifeline to Africa disrupted by Iran war', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (359925000429569, '2026-05-27 14:35:31.972708', 295514619002880, NULL, NULL, '', NULL, NULL, 'Heatstroke has killed at least 16 people in southern Telangana state, and Prime Minister Modi has said Indians must heed warning signs. The heat wave has also sparked forest fires in the north.', NULL, 'https://www.dw.com/en/india-news-modi-warns-of-heat-wave-dangers/live-77307758?maca=en-rss-en-all-1573-rdf', '2026-05-27 14:21:00+00', 'India news: Modi warns of heat wave dangers', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357769555349504, '2026-05-21 12:25:00.264912', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Bundestag stimmt heute darüber ab, ob die Luftverkehrssteuer sinken soll - trotz des ökologischen Schadens. Was bedeutet das für Ticketpreise? Und ist Fliegen in Deutschland wirklich teuer als im europäischen Vergleich?', '67958172-31d1-4e4a-8c07-cf88239ebb4f', 'https://www.tagesschau.de/wirtschaft/verbraucher/flugtickets-senkung-steuer-100.html', '2026-05-21 12:21:49+00', 'Flugticket-Preise: Was bringt die Senkung der Luftverkehrssteuer?', NULL);
