INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742435438592, '2026-05-21 10:34:39.191755', 295514619002880, NULL, NULL, '', NULL, NULL, 'Twenty years after seceding from the state union with Serbia, Montenegro is seen as a Western Balkan frontrunner for EU membership but remains marked by corruption, unresolved divisions and Serbia''s political influence.', NULL, 'https://www.dw.com/en/montenegro-at-20-eu-ambitions-and-serbian-ties/a-77233006?maca=en-rss-en-all-1573-rdf', '2026-05-20 15:43:00+00', 'Montenegro at 20: EU ambitions and Serbian ties', NULL);
