INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742435438595, '2026-05-21 10:34:39.191755', 295514619002880, NULL, NULL, '', NULL, NULL, 'Despite the ongoing internet blockade in Iran, access to "Internet-Pro" is available to select groups for a fee. Access to information and communication is increasingly becoming a luxury.', NULL, 'https://www.dw.com/en/in-iran-internet-access-becomes-a-luxury-for-the-few/a-77231518?maca=en-rss-en-all-1573-rdf', '2026-05-20 14:38:00+00', 'In Iran, internet access becomes a luxury for the few', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742437048320, '2026-05-21 10:34:39.584197', 297940250853376, NULL, NULL, '', NULL, NULL, 'Nur jeder fünfte Baum in Deutschland ist gesund. Zu den Ursachen zählen Klimawandel und Monokulturen. Der Wald muss für die Zukunft umgebaut werden, um zu überleben – ein Generationenprojekt.', 'klimawandel-wald-zukunft-forstwirtschaft-100', 'https://www.deutschlandfunk.de/klimawandel-wald-zukunft-forstwirtschaft-100.html', '2026-05-21 07:32:00+00', 'Forstwirtschaft und Waldschutz in Deutschland - Der lange Weg zum gesunden Wald', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742437048321, '2026-05-21 10:34:39.584197', 297940250853376, NULL, NULL, '', NULL, NULL, 'Wenn öffentlich Musik läuft, dann fließt immer auch Geld an die GEMA. Sie leitet jährlich über eine Milliarde Euro an über 100.000 Mitglieder weiter. Nun sollen die Regeln zur Ausschüttung reformiert werden. Die Vorschläge stoßen zum Teil auf heftigen Widerstand.', 'gema-reform-kulturfoerderung-klassik-pop-ki-100', 'https://www.deutschlandfunkkultur.de/gema-reform-kulturfoerderung-klassik-pop-ki-100.html', '2026-05-20 14:43:00+00', 'E-Musik vs. U-Musik - Debatte um die GEMA-Reform: Worum es geht', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742437441536, '2026-05-21 10:34:39.680717', 297942154895360, NULL, NULL, '', NULL, NULL, 'Im Norden Chiles blickt bald eine neue Teleskopanlage auf Supernova-Überreste, die Umgebung von Pulsaren und Schwarzen Löchern und in die aktivsten Bereiche von Sternentstehungsgebieten. Dort laufen die Bauarbeiten für das Tscherenkow-Teleskop CTAO. Lorenzen, Dirk', 'gammastrahlen-teleskope-in-der-atacama-wueste-100', 'https://www.deutschlandfunk.de/gammastrahlen-teleskope-in-der-atacama-wueste-100.html', '2026-05-21 00:57:17+00', 'Energiereiches Licht - Gammastrahlen-Teleskope in der Atacama-Wüste', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742437441537, '2026-05-21 10:34:39.680717', 297942154895360, NULL, NULL, '', NULL, NULL, 'Wo genau begann der Ausbruch der Ebola-Variante Bundibugyo im Kongo? Virologen aus der Region haben das Erbgut der Virusproben analysiert. Ihr Ergebnis: Offenbar hatte alles einen einzigen Ausgangspunkt, womöglich bei einem infizierten Tier. Wildermuth, Volkart', 'virus-informationen-neuer-ebola-ausbruch-hat-offenbar-einen-ausgangspunkt-100', 'https://www.deutschlandfunk.de/virus-informationen-neuer-ebola-ausbruch-hat-offenbar-einen-ausgangspunkt-100.html', '2026-05-20 14:35:57+00', 'Epidemie in Afrika - Der Ebola-Ausbruch hat offenbar nur einen Ausgangspunkt', NULL);
