INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438084609, '2026-05-21 10:34:39.837799', 295500424519680, NULL, 'DIE ZEIT: Ausland - Maline Hofmann, Marla  Noss, Maxim Nägele', 'Ausland', NULL, NULL, 'Im lettischen Luftraum ist eine weitere Drohne gesichtet worden. Litauens Präsident bezeichnet einen vorherigen Drohnenalarm in Vilnius als wichtige Lektion. Das Liveblog', '{urn:uuid:3ae954a8-b538-466c-b076-959e512f43f2}', 'https://www.zeit.de/politik/ausland/ukraine-krieg-news-liveblog', '2026-05-21 10:24:07+00', 'Krieg gegen die Ukraine: Lettland meldet weiteren Drohnenzwischenfall im eigenen Luftraum', NULL);
