INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438088704, '2026-05-21 10:34:39.838799', 295500424519680, NULL, 'DIE ZEIT: Sport - Yannick von Eisenhart Rothe, Sophia Reddig, Leon Ginzel', 'Sport', NULL, NULL, 'Vor der gesamten Kaderbekanntgabe um 13 Uhr nominiert der DFB einzelne Spieler per Instagram-Clip. Neben vielen erwarteten Namen sticht Amiri heraus. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-05-21 10:20:05+00', 'Fußballweltmeisterschaft 2026: Mainzer Nadiem Amiri steht im deutschen WM-Kader', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438088705, '2026-05-21 10:34:39.838799', 295500424519680, NULL, 'DIE ZEIT: Ausland - Marla  Noss', 'Ausland', NULL, NULL, 'Im Iran sind zwei Männer wegen des Vorwurfs der Mitgliedschaft in einer Terrorgruppe hingerichtet worden. Die NGO Hengaw sprach von kurdischen politischen Gefangenen.', '{urn:uuid:7e654a31-a293-4b3a-a06d-3f1d8fbe456b}', 'https://www.zeit.de/politik/ausland/2026-05/hinrichtungen-iran-maenner-terrorgruppe', '2026-05-21 10:09:38+00', 'Proteste im Iran : Zwei weitere Menschen im Iran hingerichtet', NULL);
