INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438547456, '2026-05-21 10:34:39.950037', 295853820891136, NULL, NULL, '', NULL, NULL, 'Rund zwei von 1.000 Kindern in Deutschland werden gehörlos geboren. Ursache ist häufig ein Gendefekt, so wie bei der OTOF-Taubheit. Für diese gibt es nun eine Gentherapie, die laut Studien erstmals Erfolg zeigt. Von Sylvaine von Liebe.', 'a8565797-3155-467c-b88a-3c176129255c', 'https://www.tagesschau.de/wissen/forschung/gentherapie-gehoerlosigkeit-100.html', '2026-05-21 10:32:31+00', 'Gentherapie lässt genetisch-bedingt gehörlose Kinder hören', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438547457, '2026-05-21 10:34:39.950037', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Kadaver des mehrfach in der Ostsee gestrandeten Buckelwals liegt am Strand der dänischen Insel Anholt - und droht dort zu explodieren. Die Dänen versuchen nun, ihn in einen Hafen in Jütland zu ziehen.', '3d040cca-2ea2-43e9-b8c0-bd5a0cd938f2', 'https://www.tagesschau.de/ausland/europa/daenemark-kadaver-buckelwal-100.html', '2026-05-21 10:07:14+00', 'Dänemark will Kadaver von Buckelwal aufs Festland ziehen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438547458, '2026-05-21 10:34:39.950037', 295853820891136, NULL, NULL, '', NULL, NULL, 'Lange war Deutschland ein attraktiver Standort für Investitionen aus dem Ausland. Aber seit Jahren geht die Zahl der Projekte zurück. Deutschland tut zu wenig, um für Investoren interessant zu bleiben, kritisiert ein Experte.', 'f4f2114c-301b-4c16-a291-c4adbeaf8c0f', 'https://www.tagesschau.de/wirtschaft/konjunktur/investitionen-ausland-deutschland-100.html', '2026-05-21 09:48:45+00', 'Erneut weniger ausländische Investitionen in Deutschland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438547459, '2026-05-21 10:34:39.950037', 295853820891136, NULL, NULL, '', NULL, NULL, 'Rechte und rechtsextreme Akteure drängen zunehmend in Fankurven deutscher Fußballstadien. Das zeigen Monitor-Recherchen. Online und auf Veranstaltungen wird wird daran gearbeitet, sich stärker zu vernetzen. Im Fokus: die 3. Liga.', '1a305f4b-9db2-4d78-bc3e-7c674d720e1a', 'https://www.tagesschau.de/investigativ/monitor/fussball-fankurven-rechtsextremismus-100.html', '2026-05-21 09:16:03+00', 'Wie Rechte zunehmend in die Kurven deutscher Fußballstadien drängen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551552, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der DAX ist nach seiner jüngsten Erholung mit leichten Abschlägen in den Handelstag gestartet. Anleger warten auf neue Signale im Iran-Konflikt. Unterstützung kommt derweil von starken Tech-Werten.', 'e2b96e60-876b-4ef2-91b0-306945e64818', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-nikkei-nvidia-100.html', '2026-05-21 08:35:26+00', 'Marktbericht: DAX legt Verschnaufpause ein', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551553, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'In der Region rund um die italienische Stadt Neapel wurde am Morgen ein Erdbeben der Stärke 4,4 registriert. Bereits im vergangenen Jahr hatte es mehrere Beben in dem Gebiet mit hoher vulkanischer Aktivität gegeben.', '47828915-cf93-4bc4-990c-d692493daafa', 'https://www.tagesschau.de/ausland/europa/italien-neapel-erdbeben-100.html', '2026-05-21 08:15:49+00', 'Erdbeben erschüttert italienische Großstadt Neapel', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551554, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mehr als zehn Jahre lang begrüßte Stephen Colbert Gäste und Publikum der berühmten "Late Show" im US-Fernsehen - heute Abend allerdings zum letzten Mal. Nicht nur der Trump-Kritiker selbst vermutet hinter dem Abschied politische Gründe. Von G. Ucar.', '77e6db48-c1a4-45fd-928a-95703aead3d5', 'https://www.tagesschau.de/ausland/amerika/abschied-colbert-latenightshow-100.html', '2026-05-21 08:14:07+00', 'Die letzte "Late Show" mit Stephen Colbert', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551555, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die USA haben angekündigt, ihre Militärpräsenz in Europa zu reduzieren. Das trifft auch Polen - 4.000 Soldaten einer Panzerbrigade sollen vorerst nicht zurückkehren. Und ihre Zukunft bleibt ungewiss. Von F. Kellermann.', 'b49e4cae-7161-48d3-a976-05d856d9061e', 'https://www.tagesschau.de/ausland/europa/polen-nato-us-truppen-100.html', '2026-05-21 08:13:32+00', 'Polen bangt um Zukunft der US-Panzerbrigade in Niederschlesien', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551556, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Ukraine will möglichst schnell der EU beitreten - aber die Verhandlungen sind schwierig. Jetzt spricht sich Kanzler Merz für einen exklusiven Status als EU-Partner aus - und appelliert an die EU-Spitzen.', '339e6765-26e3-4882-962f-235ef83842f7', 'https://www.tagesschau.de/ausland/europa/eu-merz-ukraine-sonderstatus-100.html', '2026-05-21 08:09:31+00', 'Merz schlägt EU-Sonderstatus für Ukraine vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551557, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'Seit Monaten sitzt der Reporter Uludağ in türkischer Haft, wegen eines regierungskritischen Posts auf X. Nun hat der Prozess gegen den Deutsche-Welle-Journalisten begonnen - trotz aller Appelle. Von Isabel Gotovac.', '2d106d06-7808-4ddb-8e61-f5dba616cb68', 'https://www.tagesschau.de/ausland/europa/deutsche-welle-tuerkei-prozess-alican-uludag-100.html', '2026-05-21 08:05:33+00', 'Türkei: Prozess gegen Deutsche-Welle--Korrespondenten beginnt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438551558, '2026-05-21 10:34:39.951036', 295853820891136, NULL, NULL, '', NULL, NULL, 'Zwei Tage nach dem Hauseinsturz in Görlitz haben Einsatzkräfte in den Trümmern eine tote Frau geborgen. Zwei weitere Menschen werden noch vermisst. Laut Polizei haben die Spürhunde zweimal angeschlagen.', '10342563-afc1-42c2-8c68-ec0ddde5ba23', 'https://www.tagesschau.de/inland/regional/goerlitz-hauseinsturz-106.html', '2026-05-21 07:01:49+00', 'Hauseinsturz in Görlitz: Einsatzkräfte finden tote Frau in den Trümmern', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555648, '2026-05-21 10:34:39.952411', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nvidia wächst im KI-Boom weiter rasant, zuletzt stieg der Umsatz im Jahresvergleich um 85 Prozent. Darüber können sich auch die Aktionäre freuen: Nvidia kündigte eine deutliche Anhebung der Dividende an.', 'e5c55a8a-dd47-4984-a6c1-2217f0bbdb6f', 'https://www.tagesschau.de/wirtschaft/unternehmen/nvidia-chipkonzern-ki-gewinnsprung-100.html', '2026-05-21 06:57:03+00', 'Nvidia beschleunigt Wachstum mit 85 Prozent Umsatzplus', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555649, '2026-05-21 10:34:39.952411', 295853820891136, NULL, NULL, '', NULL, NULL, 'Wenige Tage nach US-Präsident Trump hat Chinas Staatschef Xi den russischen Präsidenten Putin empfangen. Sie betonten ihre enge Partnerschaft. Einen Dämpfer gab es aber für Putin. Von Maximilian Seib.', 'd8cbf8d8-5730-47d8-be16-614a230988e6', 'https://www.tagesschau.de/ausland/asien/treffen-putin-xi-peking-ergebnisse-100.html', '2026-05-21 05:52:05+00', 'Putin und Xi: Enge Beziehung - anders als bei Trumps Besuch', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555650, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Hohe Ölpreise und gestörte Lieferketten setzen deutsche Chemiekonzerne unter Druck. Doch die Konkurrenz in Asien trifft es härter - ein kurzfristiger Wettbewerbsvorteil für BASF, Lanxess, Evonik und Co. Von Angela Göpfert.', '66205828-1b5f-4e0a-bb02-519ec056ede2', 'https://www.tagesschau.de/wirtschaft/unternehmen/oelschock-hormus-chemie-100.html', '2026-05-21 05:25:30+00', 'Ölkrise: Warum die deutsche Chemiebranche kurz aufatmen kann', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555651, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ein russisches Militärprojekt wird von der NATO mit Sorge betrachtet. Nach Recherchen von WDR und NDR geht es dabei um die Stationierung von Atomraketen am Meeresgrund. Von Florian Flade und Antonius Kempmann.', 'acddadf1-126a-402a-a160-06b4213d1018', 'https://www.tagesschau.de/investigativ/ndr-wdr/russland-militaer-geheimprojekt-ruestung-100.html', '2026-05-21 04:12:47+00', 'Russisches Geheimprojekt "Skythen" - Atomraketen am Meeresgrund?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555652, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Im Bundestag diskutieren die Abgeordneten heute über das neue Sportfördergesetz. Athleten-Vertreter fordern Mitsprache, die Linke befürchtet eine Mogelpackung. Von Felix Tenbaum.', '9c104d07-3d4b-4b6d-ab71-7dbc8baa60b8', 'https://www.tagesschau.de/inland/gesellschaft/sportfoerderung-gesetzentwurf-100.html', '2026-05-21 02:33:17+00', 'Bundestag debattiert über neues Sportfördergesetz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555653, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Er selbst könnte dabei weltweit erster Billionär werden: Elon Musks SpaceX soll den größten Börsengang der Geschichte vollziehen. Dabei schrieb das Raumfahrtunternehmen zuletzt einen Milliardenverlust.', '35986648-d98b-4037-8b30-dd8f8c468385', 'https://www.tagesschau.de/wirtschaft/unternehmen/spacex-boersengang-100.html', '2026-05-21 00:43:55+00', 'SpaceX: Musk kündigt bislang wohl größten Börsengang an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555654, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Großbritannien erlaubt weiter den Import von Kerosin und Diesel, der aus russischem Öl raffiniert wurde. Die Opposition wirft der Regierung vor, die Ukraine zu verraten. Premier Starmer hält dagegen. Von Gabi Biesinger.', 'ac49e792-0487-4fbf-b193-b64d2d2dbede', 'https://www.tagesschau.de/ausland/europa/grossbritannien-sanktionen-russland-102.html', '2026-05-20 22:56:28+00', 'Großbritannien: Streit um Öl-Sanktionen gegen Russland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (357742438555655, '2026-05-21 10:34:39.952918', 295853820891136, NULL, NULL, '', NULL, NULL, 'Besonders die Zusammenarbeit mit Ex-Wirecard-Chef Marsalek machte den Fall zu einem der größten Spionageprozesse Österreichs. Nun ist ein Urteil gefallen: mehr als vier Jahre Haft für Ex-Verfassungsschützer Ott wegen Spionage für Russland.', '986cc42a-c4e6-41c4-8fce-3e5b7e0f4884', 'https://www.tagesschau.de/ausland/europa/urteil-spionage-egisto-ott-100.html', '2026-05-20 20:37:35+00', 'Österreich: Ex-Verfassungsschützer Ott wegen Spionage verurteilt', NULL);


