INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344648517636097, '2026-04-14 10:35:21.915531', 199268075270145, NULL, false, '', NULL, '', '', '2014-01-07', '', 'Entscheidung zur Reise', '', '2014-01-06', 'Walter überwindet seine Ängste und beschließt, den Fotografen selbst zu suchen, anstatt passiv zu bleiben oder die Situation zu akzeptieren.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344648111525888, '2026-04-14 10:33:42.767448', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Ankündigung der Schließung', '', '2014-01-04', 'Die Geschäftsleitung informiert über die Einstellung des Magazins, wodurch Unsicherheit entsteht und Mitarbeiter beginnen, sich um ihre berufliche Zukunft Sorgen zu machen.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344357723013121, '2026-04-13 14:52:07.134341', 199268075270145, '2026-04-15 10:44:17.62842', false, '', '#008080', '', '', NULL, '', 'Vorstellung von Cheryl', 'https://storage.googleapis.com/users_media_berlin/199268075270145/Cheryl.png', '2014-01-03', 'Walter bemerkt Cheryl im Büroalltag, entwickelt starke Gefühle, traut sich jedoch nicht, sie direkt anzusprechen oder seine Zuneigung offen zu zeigen.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344356884078593, '2026-04-13 14:48:42.316834', 199268075270145, '2026-04-14 12:19:25.078747', false, '', NULL, '', '', NULL, '', 'Alltag bei LIFE Magazin', 'https://storage.googleapis.com/users_media_berlin/199268075270145/$_57.jpg', '2014-01-01', 'Walter arbeitet ruhig im Fotoarchiv, meidet Risiken, lebt zurückgezogen und verbringt seine Tage in routinierten, vorhersehbaren Abläufen ohne große Veränderungen.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344652957339649, '2026-04-14 10:53:25.827068', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Bar & Hubschrauber', '', '2014-01-10', 'In einer Bar trifft Walter einen exzentrischen Piloten und fasst schließlich den Mut, in einen Helikopter zu steigen und ins kalte Meer zu springen.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344653064830977, '2026-04-14 10:53:52.070333', 199268075270145, NULL, false, '', NULL, '', '', '2014-01-12', '', 'Schiffserlebnis', '', '2014-01-11', 'Walter hilft auf einem Schiff aus, sammelt neue Erfahrungen und erkennt, dass er in realen Abenteuern mehr Selbstvertrauen entwickeln kann als gedacht.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344653183254529, '2026-04-14 10:54:20.982856', 199268075270145, NULL, false, '', NULL, '', '', '2014-01-14', '', 'Island-Ankunft', '', '2014-01-13', 'Walter folgt weiteren Hinweisen nach Island, wo er beeindruckende Landschaften erlebt und seine Suche nach dem Fotografen konsequent fortsetzt.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344653958561793, '2026-04-14 10:57:30.266416', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Skateboard-Fahrt', 'https://storage.googleapis.com/users_media_berlin/199268075270145/das-erstaunliche-leben-des-walter-mitty-dvd-ben-stiller.jpeg', '2014-01-15', 'Er nutzt ein Skateboard, um eine lange Strecke durch die Natur zurückzulegen, genießt den Moment und fühlt sich erstmals wirklich frei.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344668573782017, '2026-04-14 11:56:58.435653', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Rückkehr nach USA', '', '2014-01-17', 'Ohne endgültigen Erfolg kehrt Walter zunächst zurück, reflektiert seine Erlebnisse und beginnt, seine bisherigen Lebensentscheidungen neu zu bewerten.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344668734910465, '2026-04-14 11:57:37.773954', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Neue Spur', '', '2014-01-19', 'Eine weitere Information führt Walter schließlich auf eine neue Spur, die ihn in abgelegene Regionen bringt und neue Hoffnung weckt.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344668947103745, '2026-04-14 11:58:29.578856', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Begegnung mit Sean', '', '2014-01-23', 'Schließlich trifft Walter den Fotografen, der ihm ruhig erklärt, warum bestimmte Momente nicht fotografiert, sondern einfach erlebt werden sollten.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344670346248193, '2026-04-14 12:04:11.166613', 199268075270145, NULL, false, '', NULL, '', '', NULL, '', 'Rückkehr & Erkenntnis', '', '2014-01-25', 'Walter kehrt verändert zurück, erkennt seinen eigenen Wert und beginnt, sein Leben bewusster und selbstbestimmter zu gestalten als zuvor.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344357545488385, '2026-04-13 14:51:23.793359', 199268075270145, '2026-04-14 12:06:06.449659', false, '', NULL, '', '', NULL, '', 'Tagtraum: Superheld', 'https://x.com/gombau/status/2043623318591255024', '2014-01-02', 'In Gedanken stellt sich Walter als mutigen Helden dar, der außergewöhnliche Situationen meistert und Anerkennung erhält, die ihm im echten Leben fehlt.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344648359841793, '2026-04-14 10:34:43.391184', 199268075270145, '2026-04-14 12:08:58.020236', false, '', NULL, '', '', NULL, '', 'Negativ 25 fehlt', 'https://www.tiktok.com/@gssh.hwus/video/7517830297400954167', '2014-01-05', 'Ein entscheidendes Foto fehlt plötzlich, wodurch Walters Arbeit unter Druck gerät, da dieses Bild für die letzte Ausgabe unverzichtbar ist.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344649316683777, '2026-04-14 10:38:36.995027', 199268075270145, '2026-04-14 12:10:42.347495', false, '', '#8dcee0', '', '', '2014-01-09', '', 'Reise nach Grönland', 'https://www.google.com/maps/place/Nuuk,+Gr%C3%B6nland/@64.2664099,-52.5214701,9.25z/data=!4m6!3m5!1s0x4ea20dce1ab32725:0x3de425fb4d692306!8m2!3d64.1743234!4d-51.7372787!16zL20vMGRfMW0?entry=ttu&g_ep=EgoyMDI2MDQwOC4wIKXMDSoASAFQAw%3D%3D', '2014-01-08', 'Ohne große Planung begibt sich Walter auf eine unerwartete Reise nach Grönland, wo er beginnt, seine Komfortzone deutlich zu verlassen.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344668656336897, '2026-04-14 11:57:18.590205', 199268075270145, '2026-04-27 09:07:41.606314', false, '', NULL, '', '', NULL, '', 'Konflikt im Büro', 'https://www.youtube.com/watch?v=MmNJaXSjw6U', '2014-01-18', 'Im Büro eskaliert die Situation, Walter verliert seinen Job und steht vor ungewisser Zukunft, da das wichtige Foto weiterhin fehlt.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344670418812929, '2026-04-14 12:04:28.882996', 199268075270145, '2026-04-14 12:19:50.502133', false, '', NULL, '', '', NULL, '', 'Titelbild enthüllt', 'https://storage.googleapis.com/users_media_berlin/199268075270145/Walter-Mitty-3-Michael-Tersieff-806x1024.jpg', '2014-01-26', 'Das letzte Titelbild zeigt Walter selbst bei der Arbeit, wodurch seine unscheinbare Rolle als bedeutend und würdig anerkannt wird.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344668485283841, '2026-04-14 11:56:36.829847', 199268075270145, '2026-04-27 08:26:35.44596', false, '', NULL, '', '', NULL, '', 'Vulkan-Ausbruch', 'https://www.youtube.com/watch?v=Hnt9xLxQVN0', '2014-01-16', 'Ein plötzlich ausbrechender Vulkan zwingt Walter zur Flucht, wodurch er eine gefährliche Situation meistert und weiter an Selbstvertrauen gewinnt.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344668855078913, '2026-04-14 11:58:07.111676', 199268075270145, '2026-04-27 09:11:09.75883', false, '', NULL, '', '', '2014-01-22', '', 'Reise nach Afghanistan', 'https://www.fbw-filmbewertung.com/uploads/fbwdb_film/gallery/10035/3ab12c249102d296908dc3c9e546c66faf2c46af.jpg', '2014-01-20', 'Walter reist in eine abgelegene Bergregion, wo er schwierige Bedingungen meistert und sich zunehmend als entschlossener und mutiger Mensch entwickelt.', 'EVENT', NULL);
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344356758548481, '2026-04-13 14:48:11.669125', 199268075270145, '2026-04-27 09:13:26.374104', false, '', '#000000', '', '', '2014-01-26', '', 'Das erstaunliche Leben des Walter Mitty', 'https://storage.googleapis.com/users_media_berlin/199268075270145/HFxoLyiXcAAHi5m.jpg', '2014-01-01', 'Wenn sein Job und der seines Mitarbeiters bedroht sind, handelt Walter in der realen Welt und begibt sich auf eine globale Reise, die sich in ein außergewöhnlicheres Abenteuer verwandelt, als er es sich je hätte vorstellen können.', 'TITLE', '2026-04-27 09:13:26.368768');
INSERT INTO public.timelineslides (id, createdat, secondarykey, updatedat, autolink, backgroundalt, backgroundcolor, backgroundurl, displaydate, enddate, groupid, headline, media, startdate, text, type, lastupdated) VALUES (344670238445569, '2026-04-14 12:03:44.847579', 199268075270145, '2026-04-27 09:13:26.374104', false, '', NULL, '', '', NULL, '', 'Schneeleopard-Szene', 'https://vimeo.com/230576351', '2014-01-24', 'Gemeinsam beobachten sie einen seltenen Schneeleoparden, wobei Walter versteht, dass besondere Augenblicke oft ohne Kamera intensiver wahrgenommen werden.', 'EVENT', NULL);


